"use client"

import { usePathname } from 'next/navigation'
import BootLoader from '@/components/BootLoader'
import Navbar from '@/components/Navbar'
import Footer from '@/components/Footer'
import CommandPalette from '@/components/CommandPalette'
import PresenceHandler from '@/components/PresenceHandler'
import SessionManager from '@/components/SessionManager'
import { useEffect, useState } from 'react'

import { SearchProvider } from '@/context/SearchContext'
import { ThemeProvider } from '@/context/ThemeContext'

export default function ClientLayout({
  children,
}: {
  children: React.ReactNode
}) {
  const pathname = usePathname()
  const [isPageMounted, setIsPageMounted] = useState(false)

  useEffect(() => {
    setIsPageMounted(true)
    return () => setIsPageMounted(false)
  }, [pathname])

  const isMessages = pathname?.startsWith('/messages')
  const isProfile = pathname?.startsWith('/profile')
  const isAuth = pathname?.startsWith('/auth')

  return (
    <ThemeProvider>
      <SearchProvider>
        <BootLoader />
        <div className="mesh-gradient-bg" />
        <div className="glow-blob" />
        <div className="glow-blob" style={{ animationDelay: '-5s', left: '60%', top: '40%' }} />
        <div className="glow-blob" style={{ animationDelay: '-10s', left: '10%', top: '70%', width: '600px', height: '600px', opacity: 0.02 }} />
        <div className="glow-blob" style={{ animationDelay: '-15s', left: '80%', top: '20%', width: '400px', height: '400px', opacity: 0.02 }} />
        {!isMessages && !isAuth && <Navbar />}
        <main className={`min-h-screen ${!isMessages && !isAuth ? 'pt-4' : ''} transition-all duration-700 ease-out ${isPageMounted ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-4'}`}>
          {children}
        </main>
        {!isMessages && !isAuth && <Footer />}
        <CommandPalette />
        <PresenceHandler />
        <SessionManager />
      </SearchProvider>
    </ThemeProvider>
  )
}

"use client"

import { useEffect, useState } from 'react'
import { createClient } from '@/lib/supabase/client'
import { 
  Bug, 
  CheckCircle2, 
  Clock, 
  User, 
  MessageSquare,
  AlertCircle,
  TrendingUp,
  Filter,
  ExternalLink,
  ChevronDown
} from 'lucide-react'
import { motion, AnimatePresence } from 'framer-motion'
import { useCsrfToken } from '@/hooks/useCsrfToken'

export default function IssuesManagement() {
  const supabase = createClient()
  const { token: csrfToken } = useCsrfToken()
  const [issues, setIssues] = useState<any[]>([])
  const [loading, setLoading] = useState(true)
  const [filter, setFilter] = useState('open')

  const fetchIssues = async () => {
    setLoading(true)
    let query = supabase.from('issue_reports').select('*, users(username, display_name)')

    if (filter !== 'all') query = query.eq('status', filter)

    const { data } = await query.order('created_at', { ascending: false })
    setIssues(data || [])
    setLoading(false)
  }

  useEffect(() => {
    fetchIssues()
  }, [filter])

  const resolveIssue = async (id: string) => {
    if (!csrfToken) return alert('CSRF missing.')
    const { data: { user } } = await supabase.auth.getUser()

    await supabase.from('issue_reports').update({ 
      status: 'closed',
      updated_at: new Date().toISOString()
    }).eq('id', id)

    await supabase.from('admin_audit_log').insert({
      admin_id: user?.id,
      action: 'resolve_issue',
      target_type: 'issue',
      target_id: id
    })

    fetchIssues()
  }

  return (
    <div className="space-y-8">
      <header className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
           <h1 className="text-4xl font-black tracking-tighter mb-2 text-foreground">Build Errors</h1>
           <p className="text-foreground/40 text-sm font-medium tracking-tight">Technical support tickets and system bug reports from the community.</p>
        </div>
        <div className="flex items-center gap-2">
           <button onClick={() => setFilter('open')} className={`px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${filter === 'open' ? 'bg-orange-500 text-black shadow-lg shadow-orange-500/20' : 'bg-foreground/5 text-foreground/40'}`}>Triage Required</button>
           <button onClick={() => setFilter('all')} className={`px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${filter === 'all' ? 'bg-foreground/10 text-foreground' : 'bg-foreground/5 text-foreground/40'}`}>All Archive</button>
        </div>
      </header>

      <div className="grid grid-cols-1 gap-4">
        {loading ? (
             <div className="p-20 flex justify-center"><div className="w-8 h-8 border-2 border-orange-500/20 border-t-orange-500 rounded-full animate-spin" /></div>
        ) : issues.length > 0 ? (
          issues.map((issue, i) => (
            <motion.div 
              initial={{ opacity: 0, scale: 0.98 }}
              animate={{ opacity: 1, scale: 1 }}
              transition={{ delay: i * 0.05 }}
              key={issue.id}
              className="bg-card border border-border rounded-3xl p-8 hover:border-border transition-all group flex flex-col md:flex-row gap-8"
            >
               <div className="flex-1 space-y-4">
                  <div className="flex items-center gap-3">
                     <div className={`p-2 rounded-lg bg-orange-500/10 text-orange-500`}>
                        <Bug size={16} />
                     </div>
                     <span className="text-[10px] font-black uppercase tracking-widest text-orange-500">Bug Report</span>
                     <span className="text-[10px] font-mono text-foreground/40 uppercase flex items-center gap-1.5"><Clock size={10} /> {new Date(issue.created_at).toLocaleString()}</span>
                  </div>

                  <div className="space-y-2">
                     <h3 className="text-xl font-black tracking-tight text-foreground">{issue.title || 'Untitled Issue'}</h3>
                     <p className="text-sm text-foreground/40 leading-relaxed font-medium">{issue.description}</p>
                  </div>

                  <div className="flex flex-wrap gap-4 pt-4 border-t border-border">
                     <div className="flex items-center gap-1.5 text-[10px] font-bold text-foreground/40 uppercase">
                        <User size={12} className="text-blue-500" />
                        <span className="text-foreground">@{issue.users?.username || 'anonymous'}</span>
                     </div>
                     <div className="flex items-center gap-1.5 text-[10px] font-bold text-foreground/40 uppercase">
                        <AlertCircle size={12} className="text-foreground/40" />
                        <span>Platform: Desktop/Web</span>
                     </div>
                  </div>
               </div>

               <div className="md:w-48 flex flex-col gap-2 shrink-0 self-center">
                  {issue.status === 'open' ? (
                    <button 
                      onClick={() => resolveIssue(issue.id)}
                      className="w-full py-4 bg-orange-500 text-black rounded-2xl text-[9px] font-black uppercase tracking-[0.2em] shadow-lg shadow-orange-500/10 hover:bg-orange-400 transition-all flex items-center justify-center gap-2"
                    >
                      <CheckCircle2 size={14} /> Mark Resolved
                    </button>
                  ) : (
                    <div className="p-4 bg-green-500/5 border border-green-500/10 rounded-2xl text-center">
                       <CheckCircle2 size={16} className="mx-auto text-green-500 mb-2" />
                       <p className="text-[9px] font-black uppercase tracking-widest text-green-500">Fixed & Verified</p>
                    </div>
                  )}
                  <button className="w-full py-4 bg-foreground/5 border border-border rounded-2xl text-[9px] font-black uppercase tracking-[0.2em] text-foreground/40 hover:bg-foreground/10 hover:text-foreground transition-all flex items-center justify-center gap-2">
                    <MessageSquare size={14} /> Respond
                  </button>
               </div>
            </motion.div>
          ))
        ) : (
          <div className="p-20 text-center opacity-30">
             <Bug size={48} className="mx-auto mb-4" />
             <p className="font-black uppercase tracking-widest">System Stable. No open issues.</p>
          </div>
        )}
      </div>
    </div>
  )
}

"use client"

import { useEffect, useState } from 'react'
import { createClient } from '@/lib/supabase/client'
import { 
  Flag, 
  User, 
  FileText, 
  AlertTriangle, 
  CheckCircle2, 
  Trash2, 
  ExternalLink,
  MoreVertical,
  Clock,
  Filter,
  RefreshCcw
} from 'lucide-react'
import { motion, AnimatePresence } from 'framer-motion'
import { useCsrfToken } from '@/hooks/useCsrfToken'

export default function ReportsQueue() {
  const supabase = createClient()
  const { token: csrfToken } = useCsrfToken()
  const [reports, setReports] = useState<any[]>([])
  const [loading, setLoading] = useState(true)
  const [filter, setFilter] = useState('pending')

  const fetchReports = async () => {
    setLoading(true)
    let query = supabase.from('reports').select(`
      *,
      reporter:users!reports_reporter_id_fkey(username, display_name),
      target_user:users!reports_target_user_id_fkey(username, display_name)
    `)

    if (filter !== 'all') query = query.eq('status', filter)

    const { data } = await query.order('created_at', { ascending: false })
    setReports(data || [])
    setLoading(false)
  }

  useEffect(() => {
    fetchReports()
  }, [filter])

  const resolveReport = async (id: string, resolution: string) => {
    if (!csrfToken) return alert('CSRF missing.')
    const { data: { user } } = await supabase.auth.getUser()

    await supabase.from('reports').update({ 
      status: 'resolved', 
      resolution: resolution,
      resolved_at: new Date().toISOString()
    }).eq('id', id)

    await supabase.from('admin_audit_log').insert({
      admin_id: user?.id,
      action: 'resolve_report',
      target_type: 'report',
      target_id: id,
      details: { resolution }
    })

    fetchReports()
  }

  return (
    <div className="space-y-8">
       <header className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
           <h1 className="text-4xl font-black tracking-tighter mb-2 text-foreground">Sanitation Queue</h1>
           <p className="text-foreground/40 text-sm font-medium tracking-tight">Review and resolve user-submitted violation reports.</p>
        </div>
        <div className="flex items-center gap-2">
           <button onClick={() => setFilter('pending')} className={`px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${filter === 'pending' ? 'bg-red-500 text-black shadow-lg shadow-red-500/20' : 'bg-foreground/5 text-foreground/40'}`}>Pending</button>
           <button onClick={() => setFilter('all')} className={`px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${filter === 'all' ? 'bg-foreground/10 text-foreground' : 'bg-foreground/5 text-foreground/40'}`}>History</button>
           <button onClick={fetchReports} className="p-2 bg-foreground/5 rounded-xl text-foreground/40 hover:text-foreground transition-all"><RefreshCcw size={16} /></button>
        </div>
      </header>

      <div className="grid grid-cols-1 gap-4">
        {loading ? (
             <div className="p-20 flex justify-center"><div className="w-8 h-8 border-2 border-red-500/20 border-t-red-500 rounded-full animate-spin" /></div>
        ) : reports.length > 0 ? (
          reports.map((report, i) => (
            <motion.div 
              initial={{ opacity: 0, y: 10 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: i * 0.05 }}
              key={report.id}
              className="bg-card border border-border rounded-3xl p-8 transition-all group"
            >
              <div className="flex flex-col md:flex-row gap-8">
                 <div className="flex-1 space-y-4">
                    <div className="flex items-center gap-3">
                       <span className="px-2 py-1 bg-red-500/10 border border-red-500/20 text-red-500 text-[8px] font-black uppercase tracking-widest rounded-lg">High Severity</span>
                       <span className="text-[10px] font-mono text-foreground/40 uppercase flex items-center gap-1.5"><Clock size={10} /> {new Date(report.created_at).toLocaleString()}</span>
                    </div>

                    <div className="space-y-1">
                       <div className="flex items-center gap-2 text-xs font-bold text-foreground/40">
                          <User size={12} className="text-red-500" />
                          <span className="text-foreground">@{report.reporter?.username}</span> reported 
                          {report.target_user_id ? (
                            <span className="text-red-400">@{report.target_user?.username}</span>
                          ) : (
                            <span className="text-blue-400">Post ID: {report.target_post_id}</span>
                          )}
                       </div>
                       <h3 className="text-lg font-black tracking-tight text-foreground">{report.reason}</h3>
                       <p className="text-sm text-foreground/40 leading-relaxed italic">"{report.details || 'No additional details provided.'}"</p>
                    </div>

                    <div className="flex items-center gap-3 pt-2">
                       {report.target_post_id && (
                         <button 
                           onClick={() => window.open(`/post/${report.target_post_id}`, '_blank')}
                           className="flex items-center gap-2 px-4 py-2 bg-foreground/5 hover:bg-foreground/10 rounded-xl text-[9px] font-black uppercase tracking-widest transition-all"
                         >
                           <FileText size={12} /> View Log
                         </button>
                       )}
                       {report.target_user_id && (
                         <button 
                            onClick={() => window.open(`/profile/${report.target_user?.username}`, '_blank')}
                            className="flex items-center gap-2 px-4 py-2 bg-foreground/5 hover:bg-foreground/10 rounded-xl text-[9px] font-black uppercase tracking-widest transition-all"
                         >
                           <User size={12} /> View Target
                         </button>
                       )}
                    </div>
                 </div>

                 <div className="md:w-64 flex flex-col gap-2 shrink-0">
                    {report.status === 'pending' ? (
                      <>
                        <button 
                          onClick={() => resolveReport(report.id, 'dismissed')}
                          className="w-full py-4 bg-foreground/5 border border-border rounded-2xl text-[9px] font-black uppercase tracking-[0.2em] text-foreground/40 hover:bg-foreground/10 hover:text-foreground transition-all flex items-center justify-center gap-2"
                        >
                          <CheckCircle2 size={14} /> Dismiss
                        </button>
                        <button 
                          onClick={() => resolveReport(report.id, 'taken_action')}
                          className="w-full py-4 bg-red-600 text-black rounded-2xl text-[9px] font-black uppercase tracking-[0.2em] hover:bg-red-500 transition-all flex items-center justify-center gap-2"
                        >
                          <AlertTriangle size={14} /> Action Taken
                        </button>
                      </>
                    ) : (
                      <div className="p-4 bg-green-500/5 border border-green-500/10 rounded-2xl text-center">
                         <p className="text-[9px] font-black uppercase tracking-widest text-green-500 mb-1">Resolved</p>
                         <p className="text-[10px] text-foreground/40 font-bold uppercase">{report.resolution}</p>
                      </div>
                    )}
                 </div>
              </div>
            </motion.div>
          ))
        ) : (
          <div className="p-20 text-center opacity-30">
             <Flag size={48} className="mx-auto mb-4" />
             <p className="font-black uppercase tracking-widest">Queue Clear. No reports pending.</p>
          </div>
        )}
      </div>
    </div>
  )
}

"use client"

import { useEffect, useState } from 'react'
import { createClient } from '@/lib/supabase/client'
import { 
  ShieldAlert, 
  MapPin, 
  Globe, 
  User, 
  CheckCircle2, 
  AlertTriangle,
  Server,
  Activity,
  Filter,
  RefreshCcw,
  ExternalLink
} from 'lucide-react'
import { motion, AnimatePresence } from 'framer-motion'

export default function SecurityDashboard() {
  const supabase = createClient()
  const [alerts, setAlerts] = useState<any[]>([])
  const [stats, setStats] = useState<any>({
    total: 0,
    critical: 0,
    resolved: 0
  })
  const [loading, setLoading] = useState(true)
  const [filter, setFilter] = useState('all')

  const fetchAlerts = async () => {
    setLoading(true)
    let query = supabase.from('security_alerts').select('*, users(username, display_name)')

    if (filter === 'unresolved') query = query.eq('resolved', false)
    if (filter === 'resolved') query = query.eq('resolved', true)

    const { data } = await query.order('created_at', { ascending: false })
    setAlerts(data || [])

    // Fetch stats
    const { count: total } = await supabase.from('security_alerts').select('*', { count: 'exact', head: true })
    const { count: critical } = await supabase.from('security_alerts').select('*', { count: 'exact', head: true }).eq('resolved', false)
    const { count: resolved } = await supabase.from('security_alerts').select('*', { count: 'exact', head: true }).eq('resolved', true)

    setStats({ total, critical, resolved })
    setLoading(false)
  }

  useEffect(() => {
    fetchAlerts()
  }, [filter])

  const resolveAlert = async (id: string) => {
    await supabase.from('security_alerts').update({ resolved: true }).eq('id', id)
    fetchAlerts()
  }

  const getAlertColor = (type: string) => {
    switch(type) {
      case 'brute_force':
      case 'unauthorized_access': return 'text-red-500 bg-red-500/10 border-red-500/20';
      case 'suspicious_ip': return 'text-orange-500 bg-orange-500/10 border-orange-500/20';
      case 'multiple_failures': return 'text-yellow-500 bg-yellow-500/10 border-yellow-500/20';
      default: return 'text-blue-500 bg-blue-500/10 border-blue-500/20';
    }
  }

  return (
    <div className="space-y-8">
      <header className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
           <h1 className="text-4xl font-black tracking-tighter mb-2 flex items-center gap-3">
             <ShieldAlert className="text-red-500" size={32} /> Intrusion Detection
           </h1>
           <p className="text-foreground/40 text-sm font-medium tracking-tight">Monitoring real-time threats and suspicious network activity.</p>
        </div>
        <div className="flex items-center gap-2">
           <button 
             onClick={() => setFilter('unresolved')}
             className={`px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${filter === 'unresolved' ? 'bg-red-500 text-black' : 'bg-white/5 text-gray-400 hover:bg-white/10'}`}
           >
             Unresolved
           </button>
           <button 
             onClick={() => setFilter('all')}
             className={`px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${filter === 'all' ? 'bg-foreground/10 text-foreground' : 'bg-foreground/5 text-foreground/40 hover:bg-foreground/10'}`}
           >
             All Logs
           </button>
           <button onClick={fetchAlerts} className="p-2 rounded-xl bg-foreground/5 text-foreground/40 hover:text-foreground transition-all">
             <RefreshCcw size={16} />
           </button>
        </div>
      </header>

      {/* Security Stats */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        {[
          { label: 'Pending Threats', value: stats.critical, icon: ShieldAlert, color: 'text-red-500' },
          { label: 'Resolved Incidents', value: stats.resolved, icon: CheckCircle2, color: 'text-green-500' },
          { label: 'Total Events', value: stats.total, icon: Activity, color: 'text-blue-500' },
        ].map((stat) => (
          <div key={stat.label} className="bg-card border border-border rounded-3xl p-6 flex items-center justify-between">
            <div>
               <p className="text-[10px] font-black uppercase tracking-widest text-foreground/40 mb-1">{stat.label}</p>
               <p className="text-3xl font-black text-foreground">{stat.value || 0}</p>
            </div>
            <div className={`p-4 rounded-2xl bg-foreground/5 ${stat.color}`}>
               <stat.icon size={24} />
            </div>
          </div>
        ))}
      </div>

      {/* Alerts Table-style List */}
      <div className="bg-card border border-border rounded-[2.5rem] overflow-hidden">
        <div className="p-8 border-b border-border flex items-center justify-between bg-foreground/[0.02]">
           <h3 className="text-xs font-black uppercase tracking-widest flex items-center gap-2 text-foreground">
             <Filter size={14} className="text-foreground/40" /> Security Event Stream
           </h3>
           <span className="text-[10px] font-mono text-foreground/20">Updated in real-time</span>
        </div>

        <div className="flex flex-col">
          {loading ? (
             <div className="p-20 flex justify-center">
               <div className="w-8 h-8 border-2 border-red-500/20 border-t-red-500 rounded-full animate-spin" />
             </div>
          ) : alerts.length > 0 ? (
            alerts.map((alert, i) => (
              <motion.div 
                initial={{ opacity: 0, x: -20 }}
                animate={{ opacity: 1, x: 0 }}
                transition={{ delay: i * 0.05 }}
                key={alert.id} 
                className={`p-6 border-b border-white/5 hover:bg-white/[0.02] transition-all group flex flex-col md:flex-row md:items-center gap-6 ${alert.resolved ? 'opacity-50' : ''}`}
              >
                <div className="flex-1 space-y-3">
                   <div className="flex items-center gap-3">
                      <span className={`px-2 py-1 rounded text-[8px] font-black uppercase tracking-widest border ${getAlertColor(alert.type)}`}>
                        {alert.type.replace(/_/g, ' ')}
                      </span>
                      <span className="text-[10px] font-mono text-gray-500">
                        {new Date(alert.created_at).toLocaleString()}
                      </span>
                   </div>

                   <h4 className="text-sm font-bold text-foreground leading-snug">
                     {alert.details?.message || 'Unauthorized access attempt detected'}
                   </h4>

                   <div className="flex flex-wrap gap-4 text-[10px] font-medium text-foreground/40 uppercase tracking-tight">
                      <div className="flex items-center gap-1.5">
                        <Globe size={12} className="text-blue-500" />
                        <span className="text-foreground font-mono">{alert.ip_address}</span>
                      </div>
                      <div className="flex items-center gap-1.5">
                        <MapPin size={12} className="text-orange-500" />
                        <span>{alert.details?.region || alert.details?.geo?.city || 'Unknown Location'}</span>
                      </div>
                      {alert.users && (
                        <div className="flex items-center gap-1.5">
                          <User size={12} className="text-purple-500" />
                          <span className="text-purple-500">@{alert.users.username}</span>
                        </div>
                      )}
                      <div className="flex items-center gap-1.5">
                        <Server size={12} className="text-foreground/40" />
                        <span className="truncate max-w-[200px]">{alert.details?.path || '/'}</span>
                      </div>
                   </div>
                </div>

                <div className="flex items-center gap-3 shrink-0">
                   <button 
                     onClick={() => {
                       window.open(`https://www.abuseipdb.com/check/${alert.ip_address}`, '_blank')
                     }}
                     className="p-3 rounded-xl bg-foreground/5 border border-border text-foreground/40 hover:text-foreground hover:bg-foreground/10 transition-all flex items-center gap-2 text-[9px] font-black uppercase tracking-widest"
                   >
                     <ExternalLink size={14} /> Check IP
                   </button>
                   {!alert.resolved && (
                     <button 
                       onClick={() => resolveAlert(alert.id)}
                       className="p-3 rounded-xl bg-green-500/10 border border-green-500/20 text-green-500 hover:bg-green-500 hover:text-black transition-all flex items-center gap-2 text-[9px] font-black uppercase tracking-widest"
                     >
                       <CheckCircle2 size={14} /> Resolve Alert
                     </button>
                   )}
                </div>
              </motion.div>
            ))
          ) : (
            <div className="p-20 flex flex-col items-center justify-center text-center">
              <div className="w-16 h-16 rounded-3xl bg-green-500/10 border border-green-500/20 flex items-center justify-center text-green-500 mb-6">
                <ShieldCheck size={32} />
              </div>
              <h4 className="text-lg font-bold mb-2 uppercase tracking-tighter text-foreground">Security Ledger Clean</h4>
              <p className="text-sm text-foreground/40 max-w-xs leading-relaxed">No intrusion attempts or suspicious activity detected in the current filter.</p>
            </div>
          )}
        </div>
      </div>
    </div>
  )
}

function ShieldCheck(props: any) {
  return (
    <svg 
      {...props}
      xmlns="http://www.w3.org/2000/svg" 
      width="24" 
      height="24" 
      viewBox="0 0 24 24" 
      fill="none" 
      stroke="currentColor" 
      strokeWidth="2" 
      strokeLinecap="round" 
      strokeLinejoin="round"
    >
