"use client"

import { useState } from 'react'
import { createClient } from '@/lib/supabase/client'
import { Github, Mail, Lock, LogIn, ArrowRight, UserPlus, AlertCircle, AtSign } from 'lucide-react'
import Link from 'next/link'
import { motion, AnimatePresence } from 'framer-motion'

export default function LoginPage() {
  const [email, setEmail] = useState('')
  const [password, setPassword] = useState('')
  const [isLogin, setIsLogin] = useState(true)
  const [isLoading, setIsLoading] = useState(false)
  const [error, setError] = useState<string | null>(null)

  const [username, setUsername] = useState('')

  const supabase = createClient()

  const getURL = () => {
    let url =
      process?.env?.NEXT_PUBLIC_SITE_URL ?? // Set this to your site URL in production environmental variables.
      process?.env?.NEXT_PUBLIC_VERCEL_URL ?? // Automatically set by Vercel.
      'http://localhost:3000/'
    // Make sure to include `https://` when not localhost.
    url = url.includes('http') ? url : `https://${url}`
    // Make sure to include a trailing `/`.
    url = url.charAt(url.length - 1) === '/' ? url : `${url}/`
    return url
  }

  const handleOAuth = async (provider: 'github' | 'google') => {
    setIsLoading(true)
    setError(null)
    const { error } = await supabase.auth.signInWithOAuth({
      provider,
      options: {
        redirectTo: `${getURL()}auth/callback`,
      },
    })
    if (error) {
      setError(error.message)
      setIsLoading(false)
    }
  }

  const handleEmailAuth = async (e: React.FormEvent) => {
    e.preventDefault()
    setIsLoading(true)
    setError(null)

    if (!isLogin && !username) {
      setError("Username is required")
      setIsLoading(false)
      return
    }

    const { error } = isLogin 
      ? await supabase.auth.signInWithPassword({ email, password })
      : await supabase.auth.signUp({ 
          email, 
          password,
          options: {
            emailRedirectTo: `${getURL()}auth/callback`,
            data: {
              username: username.toLowerCase(),
            }
          }
        })

    if (error) {
      setError(error.message)
      setIsLoading(false)
    } else if (!isLogin) {
      setError("Check your email for the confirmation link!")
      setIsLoading(false)
    } else {
      setIsLoading(false)
    }
  }

  return (
    <div className="min-h-screen bg-background flex flex-col items-center justify-center p-4 relative overflow-hidden">
      {/* Background Glows */}
      <motion.div 
        initial={{ opacity: 0, scale: 0.8 }}
        animate={{ opacity: 1, scale: 1 }}
        transition={{ duration: 1.5, ease: "easeOut" }}
        className="absolute top-1/4 left-1/4 w-96 h-96 bg-blue-600/10 blur-[120px] rounded-full pointer-events-none" 
      />
      <motion.div 
        initial={{ opacity: 0, scale: 0.8 }}
        animate={{ opacity: 1, scale: 1 }}
        transition={{ duration: 1.5, ease: "easeOut", delay: 0.2 }}
        className="absolute bottom-1/4 right-1/4 w-96 h-96 bg-silver/5 blur-[120px] rounded-full pointer-events-none" 
      />

      <div className="w-full max-w-md relative z-10">
        <div className="flex flex-col items-center gap-8 mb-12">
          <Link href="/" className="flex flex-col items-center gap-4 group">
            <div className="w-16 h-16 rounded-2xl border border-silver/40 flex items-center justify-center bg-[#0d0d0d] silver-glow transition-all duration-700 group-hover:rotate-[10deg] group-hover:scale-110">
              <span className="text-2xl font-bold text-silver">Ag</span>
            </div>
            <div className="flex flex-col items-center">
              <span className="text-[12px] font-black tracking-[0.6em] text-silver uppercase">ARGENTUM</span>
              <span className="text-[10px] font-bold text-gray-500 uppercase tracking-widest mt-1">Protocol of Builders</span>
            </div>
          </Link>
        </div>

        <motion.div 
          initial={{ opacity: 0, y: 40, scale: 0.95, rotateX: -10 }}
          animate={{ opacity: 1, y: 0, scale: 1, rotateX: 0 }}
          whileHover={{ scale: 1.01 }}
          whileTap={{ scale: 0.99 }}
          transition={{ 
            type: "spring",
            stiffness: 100,
            damping: 20,
            mass: 1,
            delay: 0.1
          }}
          className="glass-card p-10 border-border bg-card/50 backdrop-blur-2xl shadow-2xl relative group/card cursor-default"
          style={{ perspective: "1000px" }}
        >
          {/* Decorative Corner */}
          <div className="absolute -top-1 -right-1 w-8 h-8 border-t border-r border-silver/40 rounded-tr-xl" />

          <AnimatePresence mode="wait">
            <motion.div
              key={isLogin ? 'login' : 'signup'}
              initial={{ opacity: 0, x: -10 }}
              animate={{ opacity: 1, x: 0 }}
              exit={{ opacity: 0, x: 10 }}
              transition={{ duration: 0.3, ease: "easeInOut" }}
            >
              <h1 className="text-xl font-bold text-white mb-2 tracking-tight">
                {isLogin ? 'Welcome back, Builder' : 'Join the Protocol'}
              </h1>
              <p className="text-sm text-gray-500 mb-8 font-medium">
                {isLogin ? 'Sign in to capture your ship logs.' : 'Create an account to start your build streak.'}
              </p>
            </motion.div>
          </AnimatePresence>

          {error && (
            <div className="mb-6 p-4 rounded-xl bg-red-500/10 border border-red-500/20 flex items-center gap-3 text-red-500 text-xs font-bold animate-shake">
              <AlertCircle size={14} />
              <span>{error}</span>
            </div>
          )}

          <div className="flex flex-col gap-3 mb-8">
            <button 
