                  className="px-4 py-4 flex items-center gap-4 hover:bg-foreground/5 transition-all group border-l-2 border-transparent"
                >
                  <div className="relative">
                    <div className="w-12 h-12 rounded-full border border-border overflow-hidden bg-card flex items-center justify-center text-silver group-hover:border-foreground/20 transition-all">
                      {conv.otherParticipant.avatar_url ? (
                        <img 
                          src={conv.otherParticipant.avatar_url} 
                          alt="avatar" 
                          className="w-full h-full object-cover"
                          onError={(e) => {
                            (e.target as HTMLImageElement).style.display = 'none';
                            (e.target as HTMLImageElement).parentElement!.innerHTML = `<span class="text-sm font-black">${conv.otherParticipant.display_name?.split(' ').map((n: string) => n[0]).join('').toUpperCase() || conv.otherParticipant.username?.[0].toUpperCase()}</span>`;
                          }}
                        />
                      ) : (
                        <span className="text-sm font-black">
                          {conv.otherParticipant.display_name?.split(' ').map((n: string) => n[0]).join('').toUpperCase() || conv.otherParticipant.username?.[0].toUpperCase()}
                        </span>
                      )}
                    </div>
                  </div>

                  <div className="flex-1 min-w-0 flex flex-col gap-0.5">
                    <div className="flex items-center justify-between">
                      <span className="text-sm font-bold text-foreground truncate group-hover:silver-glow-text transition-all">
                        {conv.otherParticipant.display_name || `@${conv.otherParticipant.username}`}
                      </span>
                      {conv.lastMessageTime && (
                        <span className="text-[9px] font-bold text-gray-600 uppercase tracking-widest">
                          {conv.lastMessageTime.toLocaleDateString([], { month: 'short', day: 'numeric' })}
                        </span>
                      )}
                    </div>
                    <div className="flex items-center justify-between gap-2">
                       <p className="text-[11px] text-gray-500 truncate font-medium">
                        {conv.lastMessagePreview}
                      </p>
                      <span className="text-[10px] text-gray-700 font-bold truncate">@{conv.otherParticipant.username}</span>
                    </div>
                  </div>
                </Link>
              ))}
            </div>
          )}
        </div>

        {/* Profile Footer */}
        {user && (
           <div className="p-4 border-t border-border bg-card/50 backdrop-blur-xl">
             <div className="flex items-center gap-3 mb-4 px-2">
               <div className="w-9 h-9 rounded-xl border border-white/10 overflow-hidden bg-[#111] flex items-center justify-center text-silver font-black text-xs">
                 {profile?.avatar_url ? (
                   <img 
                    src={profile.avatar_url} 
                    className="w-full h-full object-cover"
                    onError={(e) => {
                      (e.target as HTMLImageElement).style.display = 'none';
                      (e.target as HTMLImageElement).parentElement!.innerHTML = user.email?.[0].toUpperCase();
                    }}
                  />
                 ) : user.email?.[0].toUpperCase()}
               </div>
               <div className="flex-1 min-w-0">
                 <p className="text-xs font-bold truncate text-white">{profile?.display_name || profile?.username || user.email}</p>
                 <p className="text-[10px] text-gray-600 font-mono font-bold truncate">@{profile?.username || 'user'}</p>
               </div>
             </div>

             <div className="grid grid-cols-2 gap-2">
                <Link 
                  href="/settings" 
                  className="flex items-center justify-center gap-2 p-2.5 rounded-xl bg-white/5 border border-white/5 text-[10px] font-black uppercase tracking-widest text-gray-400 hover:text-white hover:bg-white/10 transition-all font-bold"
                >
                  <Settings size={14} /> Settings
                </Link>
                <button 
                  onClick={() => setShowAccountSwitcher(true)}
                  className="flex items-center justify-center gap-2 p-2.5 rounded-xl bg-white/5 border border-white/5 text-[10px] font-black uppercase tracking-widest text-gray-400 hover:text-white hover:bg-white/10 transition-all font-bold"
                >
                  <Users size={14} /> Switch
                </button>
             </div>
           </div>
        )}
      </motion.div>

       <AccountSwitcher isOpen={showAccountSwitcher} onClose={() => setShowAccountSwitcher(false)} />

      <KeyBackupModal 
        isOpen={showBackupModal} 
        onClose={() => setShowBackupModal(false)}
        onSuccess={() => {
          setShowBackupModal(false)
          window.location.reload()
        }}
      />

      <KeyRecoveryModal 
        isOpen={showRecoveryModal}
        onClose={() => setShowRecoveryModal(false)}
        onSuccess={() => {
          setShowRecoveryModal(false)
          window.location.reload()
        }}
      />
    </div>
  )
}

"use client"

import { useState, useEffect } from 'react'
import { useRouter } from 'next/navigation'
import { createClient } from '@/lib/supabase/client'
import { hashContent } from '@/lib/utils/hash'
import { calculateStreak } from '@/lib/utils/streak'
import MarkdownEditor from '@/components/MarkdownEditor'
import { ChevronLeft, Info, Globe, Lock, Zap, Plus, Loader2 } from 'lucide-react'
import { motion } from 'framer-motion'
import Link from 'next/link'

const categories = ['Speak', 'Web3', 'AI', 'Mobile', 'DevTools', 'Game', 'Other']

export default function NewPost() {
  const [loading, setLoading] = useState(false)
  const [postType, setPostType] = useState<'log' | 'speak'>('log')
  const [isPriority, setIsPriority] = useState(false)
  const [title, setTitle] = useState('')
  const [content, setContent] = useState('')
  const [category, setCategory] = useState('Other')
  const [status, setStatus] = useState<'published' | 'private'>('published')
  const [tags, setTags] = useState('')
  const [user, setUser] = useState<any>(null)

  const router = useRouter()
  const supabase = createClient()

  useEffect(() => {
    if (!supabase) return

    const checkUser = async () => {
      const { data: { user } } = await supabase.auth.getUser()
      if (!user) {
        router.push('/')
        return
      }
      setUser(user)
    }
    checkUser()
  }, [supabase, router])

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault()
    if (!user || loading || !content || !title) return

    setLoading(true)
    try {
      // 1. Generate SHA-256 hash
      const hash = await hashContent(content)

      // 2. Save to Supabase
      const finalCategory = postType === 'speak' ? 'Speak' : category

      const { data, error } = await supabase
        .from('posts')
        .insert({
          user_id: user.id,
          title: postType === 'speak' ? `Broadcast: ${title || 'Announcement'}` : title,
          content,
          content_hash: hash,
          category: finalCategory as any,
          status,
          is_priority: isPriority,
          tags: tags.split(',').map(t => t.trim()).filter(Boolean),
          verification_status: 'unverified'
        })
        .select()
        .single()

      if (error) {
        if (error.code === '23514' && error.message.includes('posts_category_check')) {
            throw new Error("Category 'Speak' is not yet supported in the database. Please contact admin or use another category.")
        }
        throw error
      }

      // 3. Record Streak History
      const postDate = new Date().toISOString().split('T')[0]
      const { data: existingStreak } = await supabase
        .from('streak_history')
        .select('post_count')
        .eq('user_id', user.id)
        .eq('post_date', postDate)
        .single()

      if (existingStreak) {
        await supabase
          .from('streak_history')
          .update({ post_count: existingStreak.post_count + 1 })
          .eq('user_id', user.id)
          .eq('post_date', postDate)
      } else {
        await supabase
          .from('streak_history')
          .insert({
            user_id: user.id,
            post_date: postDate,
            post_count: 1
          })
      }

      // 4. Recalcalculate User Streak Count
      const { data: allHistory } = await supabase
        .from('streak_history')
        .select('post_date')
        .eq('user_id', user.id)
        .order('post_date', { ascending: false })

      if (allHistory) {
        const { current } = calculateStreak(allHistory)

        await supabase
          .from('users')
          .update({ streak_count: current })
          .eq('id', user.id)
      }

      router.push(`/post/${data.id}`)
    } catch (error: any) {
      console.error('Post creation failed:', error)
      alert(error.message || "Failed to create post. Please try again.")
    } finally {
      setLoading(false)
    }
  }

  const isSpeak = postType === 'speak'

  return (
    <div className="min-h-screen bg-background relative overflow-hidden selection:bg-silver/30">
      {/* Decorative Background */}
      <div className="absolute inset-0 noise-bg opacity-[0.03] pointer-events-none" />
      <div className="absolute top-0 right-0 w-[500px] h-[500px] bg-silver/5 blur-[120px] rounded-full -translate-y-1/2 translate-x-1/2 pointer-events-none" />
      <div className={`absolute bottom-0 left-0 w-[500px] h-[500px] blur-[120px] rounded-full translate-y-1/2 -translate-x-1/2 pointer-events-none transition-colors duration-1000 ${isSpeak ? 'bg-amber-500/10' : 'bg-blue-500/5'}`} />

      <div className="container mx-auto px-4 py-12 max-w-4xl relative z-10">
        <header className="flex items-center justify-between mb-16">
          <Link href="/" className="flex items-center gap-3 text-foreground/40 hover:text-foreground transition-all group px-4 py-2 rounded-xl bg-foreground/[0.02] border border-border/50 hover:border-border">
            <ChevronLeft size={18} className="group-hover:-translate-x-1 transition-transform" />
            <span className="text-[10px] font-black uppercase tracking-widest">Abort / Back</span>
          </Link>

          <div className="flex flex-col items-center gap-2">
            <div className="w-10 h-10 rounded-xl bg-card border border-border flex items-center justify-center silver-glow-sm">
                <Plus size={20} className="text-silver" />
            </div>
            <h1 className="text-[10px] font-black uppercase tracking-[0.4em] text-foreground/40">New Transmission</h1>
          </div>

          <div className="w-[120px]" /> {/* Spacer */}
        </header>

        <form onSubmit={handleSubmit} className="flex flex-col gap-12">
          {/* Post Type Selector */}
          <div className="flex justify-center">
            <div className="bg-card/50 backdrop-blur-xl border border-border p-1.5 rounded-2xl flex gap-1.5 shadow-2xl">
              <button
                type="button"
                onClick={() => setPostType('log')}
                className={`px-8 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${
                  postType === 'log' ? 'bg-white text-black shadow-xl ring-1 ring-white/10' : 'text-foreground/60 hover:text-foreground hover:bg-foreground/5'
                }`}
              >
                Build Log
              </button>
              <button
                type="button"
                onClick={() => setPostType('speak')}
                className={`px-8 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all flex items-center gap-2 ${
                  postType === 'speak' ? 'bg-amber-500 text-black shadow-[0_0_25px_rgba(245,158,11,0.4)]' : 'text-foreground/60 hover:text-amber-500/60 hover:bg-amber-500/5'
                }`}
              >
                <Zap size={12} className={postType === 'speak' ? 'animate-pulse' : ''} />
                Speak
              </button>
            </div>
          </div>

          <motion.div 
            layout
            className={`relative p-8 md:p-12 rounded-[3rem] border backdrop-blur-3xl shadow-3xl transition-all duration-700 ${
              isSpeak 
                ? 'bg-amber-500/[0.03] border-amber-500/30 shadow-amber-500/5' 
                : 'bg-card/30 border-border/50 shadow-black/20'
            }`}
          >
            {/* Top Section: Title */}
            <div className="flex flex-col gap-3 mb-12">
              <label className={`text-[10px] font-black uppercase tracking-[0.3em] ml-2 transition-colors ${isSpeak ? 'text-amber-500' : 'text-foreground/40'}`}>
                {isSpeak ? 'Broadcast Headline' : 'Project Identity'}
              </label>
              <input
                type="text"
                required
                value={title}
                onChange={(e) => setTitle(e.target.value)}
                placeholder={isSpeak ? "Major synchronization event..." : "Untitled build log"}
                className={`bg-transparent text-4xl md:text-6xl font-black tracking-tighter focus:outline-none placeholder:opacity-10 transition-all border-b pb-6 px-2 ${
                    isSpeak ? 'text-amber-500 border-amber-500/20' : 'text-foreground border-border/50'
                }`}
              />
            </div>

            {/* Middle Section: Meta */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8 mb-12">
              {!isSpeak && (
                <div className="flex flex-col gap-3">
                  <label className="text-[10px] font-black text-foreground/40 uppercase tracking-widest ml-1">Sector / Category</label>
                  <div className="relative group">
                    <select
                      value={category}
                      onChange={(e) => setCategory(e.target.value)}
                      className="w-full bg-background border border-border rounded-2xl px-6 py-4 text-xs font-bold focus:outline-none focus:border-foreground/40 transition-all appearance-none cursor-pointer group-hover:border-border/80"
                    >
                      {categories.map(cat => (
                        <option key={cat} value={cat}>{cat}</option>
                      ))}
                    </select>
                    <div className="absolute right-6 top-1/2 -translate-y-1/2 pointer-events-none opacity-20 group-hover:opacity-100 transition-opacity">
                        <ChevronLeft size={14} className="-rotate-90" />
                    </div>
                  </div>
                </div>
              )}

              <div className={`flex flex-col gap-3 ${isSpeak ? 'md:col-span-2' : ''}`}>
                <label className="text-[10px] font-black text-foreground/40 uppercase tracking-widest ml-1">Status / Visibility</label>
                <div className="flex gap-3 bg-background/50 p-1.5 rounded-2xl border border-border/50">
                  <button
                    type="button"
                    onClick={() => setStatus('published')}
                    className={`flex-1 flex items-center justify-center gap-3 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${
                      status === 'published' 
                        ? 'bg-foreground/5 text-foreground border border-border' 
                        : 'text-foreground/40 hover:text-foreground'
                    }`}
                  >
                    <Globe size={14} />
                    <span>Public</span>
                  </button>
                  <button
                    type="button"
                    onClick={() => setStatus('private')}
                    className={`flex-1 flex items-center justify-center gap-3 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${
                      status === 'private' 
                        ? 'bg-foreground/5 text-foreground border border-border' 
                        : 'text-foreground/40 hover:text-foreground'
                    }`}
                  >
                    <Lock size={14} />
                    <span>Private</span>
                  </button>
                </div>
              </div>
            </div>

            {/* Content Area */}
            <div className="flex flex-col gap-3 mb-10">
              <label className="text-[10px] font-black text-foreground/40 uppercase tracking-widest ml-1">
                {isSpeak ? 'Broadcast Payload' : 'The Build Log'}
              </label>
              <div className={`rounded-3xl border transition-all duration-700 overflow-hidden ${
                isSpeak ? 'bg-amber-500/[0.01] border-amber-500/20 focus-within:border-amber-500/40' : 'bg-background/20 border-border focus-within:border-foreground/20'
              }`}>
                <MarkdownEditor value={content} onChange={(val) => setContent(val || '')} />
              </div>
            </div>

            {/* Bottom Meta */}
            <div className="flex flex-col gap-3 mb-12">
              <label className="text-[10px] font-black text-foreground/40 uppercase tracking-widest ml-1">Tags</label>
              <input
                type="text"
                value={tags}
                onChange={(e) => setTags(e.target.value)}
                placeholder="web3, design, rust..."
                className="bg-background/50 border border-border rounded-2xl px-6 py-4 text-xs font-bold focus:outline-none focus:border-foreground/20 transition-all placeholder:opacity-20 translate-x-0"
              />
            </div>

            {/* Hyper-Priority Toggle */}
            <div className={`p-8 rounded-[2rem] border transition-all duration-500 overflow-hidden relative group ${
              isPriority 
                ? 'bg-amber-500/10 border-amber-500/50 shadow-[0_0_30px_rgba(245,158,11,0.1)]' 
                : 'bg-card/50 border-border hover:border-gray-800'
            }`}>
              <div className="flex flex-col md:flex-row items-start md:items-center justify-between gap-6 relative z-10">
                <div className="flex gap-4">
                  <div className={`w-14 h-14 rounded-2xl flex items-center justify-center shrink-0 transition-all duration-500 ${
                    isPriority ? 'bg-amber-500 text-black shadow-[0_0_30px_rgba(245,158,11,0.5)]' : 'bg-white/5 text-gray-500'
                  }`}>
                    <Zap size={24} className={isPriority ? 'animate-pulse' : ''} />
                  </div>
                  <div className="space-y-1.5">
                    <div className="flex items-center gap-3">
                       <h3 className={`text-xs font-black uppercase tracking-[0.2em] ${isPriority ? 'text-amber-500' : 'text-foreground'}`}>
                        Hyper-Priority Transmission
                      </h3>
                      <div className="px-2 py-0.5 rounded bg-red-500/20 border border-red-500/30">
                        <span className="text-[8px] font-black text-red-500 uppercase tracking-tighter animate-pulse">Important</span>
                      </div>
                    </div>
                    <p className={`text-[11px] leading-relaxed max-w-sm ${isPriority ? 'text-amber-500/60' : 'text-gray-500'}`}>
                      Broadcasts bypass standard filters for subscribers and appear with high-intensity visual signatures on the global network.
                    </p>
                  </div>
                </div>

                <div className="flex items-center gap-4">
                  <span className={`text-[10px] font-black uppercase tracking-widest transition-colors ${isPriority ? 'text-amber-500' : 'text-foreground/20'}`}>
                    {isPriority ? 'Activated' : 'Disabled'}
                  </span>
                  <button 
                    type="button"
                    onClick={() => setIsPriority(!isPriority)}
                    className={`relative w-16 h-8 rounded-full transition-all duration-500 outline-none ${
                      isPriority ? 'bg-amber-500 shadow-[0_0_20px_rgba(245,158,11,0.3)]' : 'bg-white/5 border border-border'
                    }`}
                  >
                    <motion.div 
                      animate={{ x: isPriority ? 36 : 4 }}
                      className={`absolute top-1 w-6 h-6 rounded-[0.6rem] shadow-xl ${
                        isPriority ? 'bg-black' : 'bg-gray-600'
                      }`}
                    />
                  </button>
                </div>
              </div>

              {isPriority && (
                 <motion.div 
                  initial={{ opacity: 0 }}
                  animate={{ opacity: 1 }}
                  className="absolute inset-0 bg-gradient-to-r from-amber-500/5 via-transparent to-amber-500/5 pointer-events-none"
                 />
              )}
            </div>

            {/* Old Info Box removed as it is now the toggle above */}

            {/* Action */}
            <button
              type="submit"
              disabled={loading || !content || !title}
              className={`w-full font-black py-6 rounded-2xl transition-all shadow-3xl active:scale-[0.98] disabled:opacity-30 disabled:grayscale uppercase tracking-[0.4em] text-xs relative overflow-hidden group border border-white/10 ${
                isSpeak 
                  ? 'bg-amber-500 text-black hover:bg-amber-400' 
                  : 'bg-white text-black hover:bg-gray-100'
              }`}
            >
              <div className="absolute inset-0 bg-white/20 translate-x-[-100%] group-hover:translate-x-[100%] transition-transform duration-1000" />
              <span className="relative z-10 flex items-center justify-center gap-3">
                {loading ? (
                    <>
                        <Loader2 className="animate-spin" size={16} />
                        <span>Synchronizing...</span>
                    </>
                ) : (
                    <>
                        {isSpeak ? <Zap size={14} /> : <Plus size={14} />}
                        <span>{isSpeak ? 'Initialize Broadcast' : 'Deploy Build Log'}</span>
                    </>
                )}
              </span>
            </button>
          </motion.div>
        </form>

        <footer className="mt-20 text-center flex flex-col items-center gap-4">
            <div className="w-1 h-8 bg-gradient-to-b from-border to-transparent" />
            <p className="text-[9px] text-foreground/20 font-black uppercase tracking-[0.3em]">
                Argentum Core Submission Layer v2.0
            </p>
        </footer>
      </div>
    </div>
  )
}

﻿"use client"

import { useEffect, useState } from 'react'
import { useRouter } from 'next/navigation'
import { createClient } from '@/lib/supabase/client'
import { 
  Bell, 
  ArrowUp, 
  MessageCircle, 
  UserPlus, 
  Lock, 
  CheckCircle, 
  Loader2, 
  Trash2, 
  CheckCheck,
  Calendar
} from 'lucide-react'
import Link from 'next/link'
import { motion, AnimatePresence } from 'framer-motion'
import { Database } from '@/types/database'
import { User } from '@supabase/supabase-js'

type NotificationWithUser = Database['public']['Tables']['notifications']['Row'] & {
  from_user: {
    id: string
    username: string
    display_name: string | null
    avatar_url: string | null
  }
}

interface NotificationGroups {
  Today: NotificationWithUser[]
  Yesterday: NotificationWithUser[]
  Older: NotificationWithUser[]
}

export default function NotificationsPage() {
  const supabase = createClient()
  const router = useRouter()
  const [loading, setLoading] = useState(true)
  const [notifications, setNotifications] = useState<NotificationWithUser[]>([])
  const [user, setUser] = useState<User | null>(null)

  useEffect(() => {
    const checkAuth = async () => {
      const { data: { user } } = await supabase.auth.getUser()
      if (!user) {
        router.push('/auth/login')
        return
      }
      setUser(user)
      await fetchNotifications(user.id)
    }

    checkAuth()
  }, [])

  const fetchNotifications = async (userId: string) => {
    try {
      const { data, error } = await supabase
        .from('notifications')
        .select(`
          *,
          from_user:users!notifications_from_user_id_fkey(id, username, display_name, avatar_url)
        `)
        .eq('user_id', userId)
        .order('created_at', { ascending: false })

      if (error) throw error
      setNotifications(data || [])
    } catch (error) {
      console.error('Error fetching notifications:', error)
    } finally {
      setLoading(false)
    }
  }

  const markAsRead = async (id: string, link?: string) => {
    try {
      await supabase
        .from('notifications')
        .update({ is_read: true })
        .eq('id', id)

      setNotifications(prev => 
        prev.map(n => n.id === id ? { ...n, is_read: true } : n)
      )

      if (link) router.push(link)
    } catch (error) {
      console.error('Error marking as read:', error)
    }
  }

  const markAllAsRead = async () => {
    if (!user) return
    try {
      await supabase
        .from('notifications')
        .update({ is_read: true })
        .eq('user_id', user.id)
        .eq('is_read', false)

      setNotifications(prev => prev.map(n => ({ ...n, is_read: true })))
    } catch (error) {
      console.error('Error marking all as read:', error)
    }
  }

  const getIcon = (type: string) => {
    switch (type) {
      case 'upvote': return <ArrowUp size={16} className="text-green-500" />
      case 'comment': return <MessageCircle size={16} className="text-blue-500" />
      case 'follow': return <UserPlus size={16} className="text-foreground/40" />
      case 'message': return <Lock size={16} className="text-green-500" />
      case 'verified': return <CheckCircle size={16} className="text-green-500" />
      default: return <Bell size={16} className="text-foreground/40" />
    }
  }

  const formatRelativeTime = (dateStr: string) => {
    const date = new Date(dateStr)
    const now = new Date()
    const diffInSeconds = Math.floor((now.getTime() - date.getTime()) / 1000)

    if (diffInSeconds < 60) return 'just now'
    if (diffInSeconds < 3600) return `${Math.floor(diffInSeconds / 60)}m ago`
    if (diffInSeconds < 86400) return `${Math.floor(diffInSeconds / 3600)}h ago`
    if (diffInSeconds < 604800) return `${Math.floor(diffInSeconds / 86400)}d ago`
    
    return date.toLocaleDateString([], { month: 'short', day: 'numeric' })
  }

  const groupNotifications = (notifs: NotificationWithUser[]): NotificationGroups => {
    const groups: NotificationGroups = {
      Today: [],
      Yesterday: [],
      Older: []
    }

    const today = new Date()
    const yesterday = new Date(today)
    yesterday.setDate(yesterday.getDate() - 1)

    notifs.forEach(n => {
      const date = new Date(n.created_at)
      if (date.toDateString() === today.toDateString()) {
        groups.Today.push(n)
      } else if (date.toDateString() === yesterday.toDateString()) {
        groups.Yesterday.push(n)
      } else {
        groups.Older.push(n)
      }
    })

    return groups
  }

  if (loading) {
    return (
      <div className="min-h-screen bg-background flex items-center justify-center">
        <Loader2 className="w-8 h-8 text-foreground/40 animate-spin" />
      </div>
    )
  }

  const grouped = groupNotifications(notifications)

  return (
    <div className="min-h-screen bg-background text-foreground selection:bg-silver/30 pb-20">
      <div className="container mx-auto px-4 py-12 max-w-2xl">
        <motion.div 
          initial={{ y: 20, opacity: 0 }}
          animate={{ y: 0, opacity: 1 }}
          className="flex flex-col gap-8"
        >
          <div className="flex items-center justify-between border-b border-border pb-6">
            <div className="flex items-center gap-4">
              <div className="w-12 h-12 rounded-2xl bg-foreground/5 border border-border flex items-center justify-center text-foreground">
                <Bell size={24} />
              </div>
              <div className="flex flex-col">
                 <h1 className="text-3xl font-black text-foreground tracking-tighter">Notifications</h1>
                 <p className="text-foreground/40 text-xs font-bold uppercase tracking-widest">Your activity feed</p>
              </div>
            </div>
            {notifications.some(n => !n.is_read) && (
              <button 
                onClick={markAllAsRead}
                className="flex items-center gap-2 px-4 py-2 rounded-xl bg-foreground/5 border border-border text-[10px] font-black uppercase tracking-widest text-foreground hover:bg-foreground/10 transition-all"
              >
                <CheckCheck size={14} />
                Mark all as read
              </button>
            )}
          </div>

          {notifications.length === 0 ? (
             <div className="glass-card p-20 flex flex-col items-center text-center gap-6 mt-10">
              <div className="w-20 h-20 rounded-[2rem] border border-border bg-card flex items-center justify-center text-foreground/40">
                <span className="text-xl font-black uppercase tracking-widest opacity-20">Ag</span>
              </div>
              <div className="flex flex-col gap-2">
                <h2 className="text-xl font-black text-foreground">No notifications yet</h2>
                <p className="text-foreground/40 text-sm">Activities from users you interact with will appear here.</p>
              </div>
            </div>
          ) : (
            <div className="flex flex-col gap-10">
              {Object.entries(grouped).map(([title, items]) => (
                items.length > 0 && (
                  <div key={title} className="flex flex-col gap-4">
                    <div className="flex items-center gap-3">
                       <span className="text-[10px] font-black text-foreground/40 uppercase tracking-[0.2em]">{title}</span>
                       <div className="h-px flex-1 bg-border" />
                    </div>
                    <div className="flex flex-col gap-2">
                      {items.map((n) => (
                        <div 
                          key={n.id}
                          onClick={() => markAsRead(n.id, n.link)}
                          className={`glass-card p-4 flex items-center gap-4 cursor-pointer hover:bg-foreground/5 transition-all group relative overflow-hidden ${
                            !n.is_read ? 'bg-foreground/[0.02] border-l-2 border-l-green-500' : 'opacity-60 grayscale-[0.5]'
                          }`}
                        >
                          <div className="w-10 h-10 rounded-full border border-border bg-card overflow-hidden flex items-center justify-center text-foreground relative z-10">
                            {n.from_user.avatar_url ? (
                              <img src={n.from_user.avatar_url} alt="avatar" className="w-full h-full object-cover" />
                            ) : (
                              <span className="text-xs font-black">
                                {n.from_user.display_name?.split(' ').map((word) => word[0]).join('').toUpperCase() || n.from_user.username?.[0].toUpperCase()}
                              </span>
                            )}
                            <div className="absolute -bottom-1 -right-1 w-5 h-5 rounded-full bg-background border border-border flex items-center justify-center shadow-xl">
                              {getIcon(n.type)}
                            </div>
                          </div>

                          <div className="flex-1 flex flex-col gap-0.5 relative z-10">
                            <p className="text-sm font-medium text-foreground/60 leading-tight">
                              <span className="text-foreground font-bold">{n.from_user.display_name || `@${n.from_user.username}`}</span> {n.content.split(n.from_user.display_name || n.from_user.username).pop()}
                            </p>
                            <span className="text-[9px] font-bold text-foreground/40 uppercase tracking-widest">
                              {formatRelativeTime(n.created_at)}
                            </span>
                          </div>

                          {!n.is_read && (
                            <div className="w-1.5 h-1.5 rounded-full bg-green-500 shadow-[0_0_10px_rgba(34,197,94,0.5)]" />
                          )}
                        </div>
                      ))}
                    </div>
                  </div>
                )
              ))}
            </div>
          )}
        </motion.div>
      </div>
    </div>
  )
}

"use client"

import { useState, useEffect } from 'react'
import { useRouter } from 'next/navigation'
import { createClient } from '@/lib/supabase/client'
import { User, AtSign, FileText, Rocket, CheckCircle2, AlertCircle, Loader2, ArrowRight, Github, Twitter, Instagram, Globe, Lock } from 'lucide-react'
import { motion, AnimatePresence } from 'framer-motion'

export default function Onboarding() {
  const [loading, setLoading] = useState(false)
  const [username, setUsername] = useState('')
  const [displayName, setDisplayName] = useState('')
  const [bio, setBio] = useState('')
  const [currentlyBuilding, setCurrentlyBuilding] = useState('')
  const [githubUsername, setGithubUsername] = useState('')
  const [twitterUsername, setTwitterUsername] = useState('')
  const [instagramUsername, setInstagramUsername] = useState('')
  const [websiteUrl, setWebsiteUrl] = useState('')
  const [skills, setSkills] = useState('')
  const [isPublic, setIsPublic] = useState(true)
  const [user, setUser] = useState<any>(null)
  const [usernameStatus, setUsernameStatus] = useState<'idle' | 'checking' | 'available' | 'taken'>('idle')
  const [usernameMessage, setUsernameMessage] = useState('')

  const router = useRouter()
  const supabase = createClient()

  useEffect(() => {
    if (!supabase) return

    const checkUser = async () => {
      const { data: { user } } = await supabase.auth.getUser()
      if (!user) {
        router.push('/auth/login')
        return
      }

      // Check if user already has a username
      const { data: profile } = await supabase
        .from('users')
        .select('username')
        .eq('id', user.id)
        .single()

      if (profile?.username) {
        router.push('/')
        return
      }

      setUser(user)

      // Auto-fill from GitHub/Google if available
      setDisplayName(user.user_metadata.full_name || user.user_metadata.name || '')
      const rawUsername = user.user_metadata.user_name || user.user_metadata.preferred_username || ''
      if (rawUsername) {
        setUsername(rawUsername.toLowerCase().replace(/[^a-z0-9_]/g, ''))
      }
    }
    checkUser()
  }, [supabase, router])

  // Real-time username check
  useEffect(() => {
    const cleanUsername = username.toLowerCase().replace(/[^a-z0-9_]/g, '')
    if (cleanUsername !== username) {
      setUsername(cleanUsername)
    }

    if (!username || username.length < 3) {
      setUsernameStatus('idle')
      setUsernameMessage('')
      return
    }

    if (username.length > 20) {
      setUsernameStatus('taken')
      setUsernameMessage('Username too long (max 20)')
      return
    }

    const checkAvailability = async () => {
      setUsernameStatus('checking')
      const { data, error } = await supabase
        .from('users')
        .select('username')
        .eq('username', username.toLowerCase())
        .single()

      if (error && error.code === 'PGRST116') { // Not found -> Available
        setUsernameStatus('available')
        setUsernameMessage('Username available')
      } else {
        setUsernameStatus('taken')
        setUsernameMessage('Username already taken')
      }
    }

    const timer = setTimeout(checkAvailability, 500)
    return () => clearTimeout(timer)
  }, [username, supabase])

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault()
    if (!user || loading || usernameStatus !== 'available') return

    setLoading(true)
    try {
      const { error } = await supabase.from('users').upsert({
        id: user.id,
        username: username.toLowerCase(),
        display_name: displayName,
        bio,
        currently_building: currentlyBuilding,
        avatar_url: user.user_metadata.avatar_url,
        github_username: githubUsername || user.user_metadata.user_name,
        twitter_username: twitterUsername || null,
        instagram_username: instagramUsername || null,
        website_url: websiteUrl || null,
        skills: skills.split(',').map((s: string) => s.trim()).filter((s: string) => s !== ''),
        is_public: isPublic,
        email: user.email
      })

      if (error) throw error

      router.push(`/profile/${username}`)
      router.refresh()
    } catch (error: any) {
      console.error('Onboarding error:', error.message)
      alert(error.message)
    } finally {
      setLoading(false)
    }
  }

  if (!user) return null

  return (
    <div className="min-h-screen bg-background flex items-center justify-center p-4">
      {/* Background Glows */}
      <div className="absolute inset-0 overflow-hidden pointer-events-none">
        <div className="absolute top-1/4 left-1/4 w-96 h-96 bg-blue-600/10 blur-[120px] rounded-full" />
        <div className="absolute bottom-1/4 right-1/4 w-96 h-96 bg-silver/5 blur-[120px] rounded-full" />
      </div>

      <motion.div 
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        className="w-full max-w-2xl relative z-10"
      >
        <div className="glass-card p-10 md:p-12 border-white/10 shadow-2xl">
          <div className="flex flex-col items-center mb-10">
            <motion.div 
              initial={{ scale: 0.8 }}
              animate={{ scale: 1 }}
              className="w-16 h-16 rounded-2xl border-2 border-silver/20 flex items-center justify-center bg-[#0d0d0d] mb-6 shadow-glow"
            >
              <span className="text-xl font-black text-silver-glow-text tracking-tighter">Ag</span>
            </motion.div>
            <h1 className="text-3xl font-black text-foreground tracking-tight text-center">Initialize Identity</h1>
            <p className="text-foreground/40 text-sm mt-3 text-center font-medium max-w-xs">
              Every builder needs a name. Claim yours on the Argentum protocol.
            </p>
          </div>

          <form onSubmit={handleSubmit} className="flex flex-col gap-8">
            {/* Username & Display Name */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="flex flex-col gap-3">
                <label className="text-[10px] font-black text-foreground/40 uppercase tracking-[0.3em] ml-1">Username</label>
                <div className="relative group">
                  <AtSign className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-600 group-focus-within:text-silver transition-colors" size={16} />
                  <input
                    type="text"
                    required
                    value={username}
                    onChange={(e) => setUsername(e.target.value.toLowerCase())}
                    maxLength={20}
                    className={`w-full bg-card border rounded-2xl pl-12 pr-12 py-4 text-sm text-foreground focus:outline-none transition-all ${
                      usernameStatus === 'available' ? 'border-green-500/30 focus:border-green-500' : 
                      usernameStatus === 'taken' ? 'border-red-500/30 focus:border-red-500' : 
                      'border-border focus:border-foreground/40'
                    }`}
                    placeholder="yourhandle"
                  />
                  <div className="absolute right-4 top-1/2 -translate-y-1/2">
                    <AnimatePresence mode="wait">
                      {usernameStatus === 'checking' && (
                        <motion.div key="loader" initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}>
                          <Loader2 className="animate-spin" size={18} />
                        </motion.div>
                      )}
                      {usernameStatus === 'available' && (
                        <motion.div key="success" initial={{ scale: 0.5, opacity: 0 }} animate={{ scale: 1, opacity: 1 }}>
                          <CheckCircle2 className="text-green-500" size={18} />
                        </motion.div>
                      )}
                      {usernameStatus === 'taken' && (
                        <motion.div key="error" initial={{ scale: 0.5, opacity: 0 }} animate={{ scale: 1, opacity: 1 }}>
                          <AlertCircle className="text-red-500" size={18} />
                        </motion.div>
                      )}
                    </AnimatePresence>
                  </div>
                </div>
              </div>

              <div className="flex flex-col gap-3">
                <label className="text-[10px] font-black text-gray-500 uppercase tracking-[0.3em] ml-1">Display Name</label>
                <div className="relative group">
                  <User className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-600 group-focus-within:text-silver transition-colors" size={16} />
                  <input
                    type="text"
                    required
                    value={displayName}
                    onChange={(e) => setDisplayName(e.target.value)}
                    className="w-full bg-card border border-border rounded-2xl pl-12 pr-4 py-4 text-sm text-foreground focus:outline-none focus:border-foreground/40 transition-all"
                    placeholder="Your full name or preferred name"
                  />
                </div>
              </div>
            </div>

            {/* Currently Building & Website */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="flex flex-col gap-3">
                <label className="text-[10px] font-black text-foreground/40 uppercase tracking-[0.3em] ml-1">Currently Building</label>
                <div className="relative group">
                  <Rocket className="absolute left-4 top-1/2 -translate-y-1/2 text-foreground/20" size={16} />
                  <input
                    type="text"
                    value={currentlyBuilding}
                    onChange={(e) => setCurrentlyBuilding(e.target.value)}
                    className="w-full bg-card border border-border rounded-2xl pl-12 pr-4 py-4 text-sm text-foreground focus:outline-none focus:border-foreground/40 transition-all"
                    placeholder="Project Alpha..."
                  />
                </div>
              </div>

              <div className="flex flex-col gap-3">
                <label className="text-[10px] font-black text-foreground/40 uppercase tracking-[0.3em] ml-1">Website URL</label>
                <div className="relative group">
                  <Globe className="absolute left-4 top-1/2 -translate-y-1/2 text-foreground/20" size={16} />
                  <input
                    type="text"
                    value={websiteUrl}
                    onChange={(e) => setWebsiteUrl(e.target.value)}
                    className="w-full bg-card border border-border rounded-2xl pl-12 pr-4 py-4 text-sm text-foreground focus:outline-none focus:border-foreground/40 transition-all"
                    placeholder="https://..."
                  />
                </div>
              </div>
            </div>

            {/* Socials */}
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              <div className="flex flex-col gap-3">
                <label className="text-[10px] font-black text-foreground/40 uppercase tracking-[0.3em] ml-1">GitHub</label>
                <div className="relative group">
                  <Github className="absolute left-4 top-1/2 -translate-y-1/2 text-foreground/20" size={14} />
                  <input
                    type="text"
                    value={githubUsername}
                    onChange={(e) => setGithubUsername(e.target.value)}
                    className="w-full bg-card border border-border rounded-xl pl-10 pr-4 py-3 text-xs text-foreground focus:outline-none focus:border-foreground/40 transition-all"
                    placeholder="handle"
                  />
                </div>
              </div>

              <div className="flex flex-col gap-3">
                <label className="text-[10px] font-black text-foreground/40 uppercase tracking-[0.3em] ml-1">X / Twitter</label>
                <div className="relative group">
                  <Twitter className="absolute left-4 top-1/2 -translate-y-1/2 text-foreground/20" size={14} />
                  <input
                    type="text"
                    value={twitterUsername}
                    onChange={(e) => setTwitterUsername(e.target.value)}
                    className="w-full bg-card border border-border rounded-xl pl-10 pr-4 py-3 text-xs text-foreground focus:outline-none focus:border-foreground/40 transition-all"
                    placeholder="handle"
                  />
                </div>
              </div>

              <div className="flex flex-col gap-3">
                <label className="text-[10px] font-black text-gray-500 uppercase tracking-[0.3em] ml-1">Instagram</label>
                <div className="relative group">
                  <Instagram className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-600" size={14} />
                  <input
                    type="text"
                    value={instagramUsername}
                    onChange={(e) => setInstagramUsername(e.target.value)}
                    className="w-full bg-white/[0.03] border border-white/5 rounded-xl pl-10 pr-4 py-3 text-xs text-white focus:outline-none focus:border-silver/40 transition-all"
                    placeholder="handle"
                  />
                </div>
              </div>
            </div>

            <div className="flex flex-col gap-3">
              <label className="text-[10px] font-black text-foreground/40 uppercase tracking-[0.3em] ml-1">Bio</label>
              <div className="relative group">
                <FileText className="absolute left-4 top-5 text-foreground/20 group-focus-within:text-foreground/60 transition-colors" size={16} />
                <textarea
                  value={bio}
                  onChange={(e) => setBio(e.target.value)}
                  className="w-full bg-card border border-border rounded-2xl pl-12 pr-4 py-4 text-sm text-foreground focus:outline-none focus:border-foreground/40 transition-all min-h-[100px] resize-none"
                  placeholder="Tell your story..."
                />
              </div>
            </div>

            {/* Skills */}
            <div className="flex flex-col gap-3">
              <label className="text-[10px] font-black text-foreground/40 uppercase tracking-[0.3em] ml-1">Skills <span className="text-foreground/20">(Comma separated)</span></label>
              <div className="relative group">
                <Rocket className="absolute left-4 top-1/2 -translate-y-1/2 text-foreground/20" size={16} />
                <input
                  type="text"
                  value={skills}
                  onChange={(e) => setSkills(e.target.value)}
                  className="w-full bg-card border border-border rounded-2xl pl-12 pr-4 py-4 text-sm text-foreground focus:outline-none focus:border-foreground/40 transition-all"
                  placeholder="Rust, React, Solidity..."
                />
              </div>
            </div>

            {/* Visibility */}
            <div className="flex flex-col gap-4 pt-4 border-t border-border">
              <label className="text-[10px] font-black text-foreground/40 uppercase tracking-[0.3em] ml-1">Profile Visibility</label>
              <div className="grid grid-cols-2 gap-6">
                <div 
                  onClick={() => setIsPublic(true)}
                  className={`cursor-pointer p-6 rounded-2xl border transition-all ${
                    isPublic 
                      ? 'bg-green-500/5 border-green-500 shadow-glow' 
                      : 'bg-card border-border hover:border-foreground/20'
                  }`}
                >
                  <div className="flex items-center gap-3 mb-2">
                    <Globe size={18} className={isPublic ? 'text-green-500' : 'text-foreground/40'} />
                    <span className={`text-sm font-bold ${isPublic ? 'text-green-500' : 'text-foreground'}`}>Public</span>
                  </div>
                  <p className="text-[10px] text-foreground/40 leading-relaxed">Anyone can view your profile and builds.</p>
                </div>

                <div 
                  onClick={() => setIsPublic(false)}
                  className={`cursor-pointer p-6 rounded-2xl border transition-all ${
                    !isPublic 
                      ? 'bg-green-500/5 border-green-500 shadow-glow' 
                      : 'bg-card border-border hover:border-foreground/20'
                  }`}
                >
                  <div className="flex items-center gap-3 mb-2">
                    <Lock size={18} className={!isPublic ? 'text-green-500' : 'text-foreground/40'} />
                    <span className={`text-sm font-bold ${!isPublic ? 'text-green-500' : 'text-foreground'}`}>Private</span>
                  </div>
                  <p className="text-[10px] text-foreground/40 leading-relaxed">Only you can see your profile.</p>
                </div>
              </div>
            </div>

            <button
              type="submit"
              disabled={loading || usernameStatus !== 'available'}
              className={`
                w-full group relative flex items-center justify-center gap-3 font-black py-5 rounded-2xl transition-all shadow-xl active:scale-[0.98] disabled:opacity-30
                ${usernameStatus === 'available' ? 'bg-foreground text-background shadow-glow' : 'bg-card text-foreground/40 border border-border'}
              `}
            >
              {loading ? (
                <Loader2 className="animate-spin" size={20} />
              ) : (
                <>
                  <span className="uppercase tracking-[0.4em] text-xs">Complete Onboarding</span>
                  <ArrowRight size={18} className="group-hover:translate-x-1 transition-transform" />
                </>
              )}
            </button>
          </form>
        </div>
      </motion.div>
    </div>
  )
}

