                  <div className="w-1 h-1 rounded-full bg-gray-800" />
                  <span className="text-[10px] font-bold uppercase tracking-wider">Builder</span>
                </div>
              </div>

              {/* Actions */}
              <div className="flex gap-3 w-full max-w-sm">
                {isOwner ? (
                  <button 
                    onClick={() => setIsEditModalOpen(true)}
                    className="flex-1 silver-metallic flex items-center justify-center gap-2 py-3 rounded-2xl text-[11px] font-black uppercase tracking-widest hover:brightness-110 active:scale-[0.98] transition-all shadow-glow"
                  >
                    <Edit3 size={14} />
                    <span>Edit Profile</span>
                  </button>
                ) : (
                  <button className="flex-1 bg-white/5 border border-white/10 hover:bg-white/10 text-white flex items-center justify-center gap-2 py-3 rounded-2xl text-[11px] font-black uppercase tracking-widest transition-all">
                    <span>Follow</span>
                  </button>
                )}
                <button className="w-12 h-12 flex items-center justify-center bg-white/5 border border-white/10 rounded-2xl text-gray-400 hover:text-white transition-all">
                  <Share2 size={18} />
                </button>
              </div>

              {/* Bio & Extended Meta */}
              <div className="flex flex-col gap-6 w-full pt-4 border-t border-border">
                {profile.bio && (
                  <p className="text-gray-400 text-sm leading-relaxed italic">
                    "{profile.bio}"
                  </p>
                )}

                <div className="flex flex-col gap-3">
                  <div className="flex items-center gap-3 text-xs text-gray-500 font-bold uppercase tracking-widest">
                    <Rocket size={14} className="text-accent" />
                    <span>Currently: <span className="text-white normal-case font-medium ml-1">{profile.currently_building || 'Analyzing protocols'}</span></span>
                  </div>
                  <div className="flex items-center gap-3 text-xs text-gray-500 font-bold uppercase tracking-widest">
                    <Calendar size={14} />
                    <span>Joined {isMounted ? new Date(profile.created_at).toLocaleDateString('en-US', { month: 'short', year: 'numeric' }) : '...'}</span>
                  </div>
                </div>

                {/* Social Links Grid */}
                <div className="grid grid-cols-1 gap-2 mt-2">
                  {profile.github_username && (
                    <Link href={`https://github.com/${profile.github_username}`} target="_blank" className="flex items-center justify-between p-3 rounded-xl bg-foreground/5 border border-border hover:bg-foreground/10 transition-all group/social">
                      <div className="flex items-center gap-3">
                        <Github size={16} className="text-foreground/40 group-hover/social:text-foreground" />
                        <span className="text-xs text-foreground/40 group-hover/social:text-foreground font-medium">{profile.github_username}</span>
                      </div>
                      <span className="text-[10px] text-foreground/40 font-bold tracking-widest uppercase">GitHub</span>
                    </Link>
                  )}
                  {profile.twitter_username && (
                    <Link href={`https://x.com/${profile.twitter_username.replace('@', '')}`} target="_blank" className="flex items-center justify-between p-3 rounded-xl bg-foreground/5 border border-border hover:bg-foreground/10 transition-all group/social">
                      <div className="flex items-center gap-3">
                        <Twitter size={16} className="text-accent-blue" />
                        <span className="text-xs text-foreground/40 group-hover/social:text-foreground font-medium">{profile.twitter_username}</span>
                      </div>
                      <span className="text-[10px] text-foreground/40 font-bold tracking-widest uppercase">X / Twitter</span>
                    </Link>
                  )}
                  {profile.website_url && (
                    <Link href={profile.website_url.startsWith('http') ? profile.website_url : `https://${profile.website_url}`} target="_blank" className="flex items-center justify-between p-3 rounded-xl bg-foreground/5 border border-border hover:bg-foreground/10 transition-all group/social">
                      <div className="flex items-center gap-3">
                        <Globe size={16} className="text-green-500" />
                        <span className="text-xs text-foreground/40 group-hover/social:text-foreground font-medium">{profile.website_url.replace(/^https?:\/\//, '')}</span>
                      </div>
                      <span className="text-[10px] text-foreground/40 font-bold tracking-widest uppercase">URL</span>
                    </Link>
                  )}
                </div>
              </div>
            </motion.div>
          </motion.div>

          {/* Main Content Feed */}
          <motion.div 
            variants={container}
            initial="hidden"
            animate="show"
            className="lg:col-span-8 flex flex-col gap-10"
          >
            {/* Extended Stats Row */}
            <motion.div variants={item} className="grid grid-cols-3 gap-4">
              <StatsCard label="Builds" value={posts?.length || 0} icon={<Zap size={20} className="text-accent" />} />
              <StatsCard label="Streak" value={profile.streak_count || 0} icon={<Flame size={20} className="text-orange-500" />} />
              <StatsCard label="Verified" value={posts?.filter((p) => p.verification_status === 'verified').length || 0} icon={<Award size={20} className="text-blue-500" />} />
            </motion.div>

            {/* Build Feed */}
            <div className="flex flex-col gap-8">
              <div className="flex items-center justify-between border-b border-white/5 pb-4">
                <h2 className="text-xs font-black text-foreground/40 uppercase tracking-[0.3em]">Build History</h2>
                <div className="flex gap-4">
                  <span className="text-[10px] font-bold text-foreground uppercase border-b border-foreground pb-1">All</span>
                  <span className="text-[11px] font-bold text-foreground/40 uppercase hover:text-foreground cursor-pointer">Releases</span>
                </div>
              </div>

              {posts && posts.length > 0 ? (
                <motion.div 
                  variants={container}
                  className="grid grid-cols-1 md:grid-cols-2 gap-6"
                >
                  {posts.map((post) => (
                    <motion.div key={post.id} variants={item}>
                      <PostCard post={post} />
                    </motion.div>
                  ))}
                </motion.div>
              ) : (
                <EmptyState 
                  title="No shipping logs found" 
                  description={isOwner 
                    ? "You haven't initialized any builds yet. Start your streak today." 
                    : `@${profile.username} is currently formulating their first build.`
                  }
                  showAction={isOwner}
                />
              )}
            </div>
          </motion.div>
        </div>
      </div>

      <EditProfileModal 
        isOpen={isEditModalOpen} 
        onClose={() => setIsEditModalOpen(false)} 
        profile={profile}
        onUpdate={handleUpdateProfile}
      />
    </div>
  )
}

function StatsCard({ label, value, icon }: { label: string, value: number, icon: React.ReactNode }) {
  return (
    <div className="glass-card p-6 flex flex-col items-center justify-center text-center gap-3 group transition-all hover:bg-white/[0.03] hover:border-white/20">
      <div className="w-12 h-12 rounded-2xl bg-foreground/5 border border-border flex items-center justify-center group-hover:scale-110 transition-transform">
        {icon}
      </div>
      <div className="flex flex-col">
        <span className="text-3xl font-black text-foreground group-hover:silver-glow-text transition-all tracking-tight">{value}</span>
        <span className="text-[10px] font-bold text-foreground/40 uppercase tracking-[0.2em] mt-1">{label}</span>
      </div>
    </div>
  )
}

"use client"

import { useEffect, useState } from 'react'
import { useRouter } from 'next/navigation'
import { createClient } from '@/lib/supabase/client'
import { 
  User, 
  Lock, 
  Bell, 
  Shield, 
  Eye, 
  EyeOff, 
  MessageSquare, 
  LogOut, 
  Trash2, 
  ChevronRight, 
  Github, 
  Chrome, 
  Download, 
  RefreshCw, 
  Layout, 
  CheckCircle2, 
  ShieldAlert,
  Moon,
  Smartphone,
  CheckCircle
} from 'lucide-react'
import { motion, AnimatePresence } from 'framer-motion'
import { User as SupabaseUser } from '@supabase/supabase-js'
import { Database } from '@/types/database'

import { useTheme } from '@/context/ThemeContext'
import { resetKeys } from '@/lib/crypto'
import { Loader2 } from 'lucide-react'

type SettingsSection = 'account' | 'privacy' | 'notifications' | 'messaging' | 'security' | 'appearance' | 'danger'

export default function SettingsPage() {
  const supabase = createClient()
  const router = useRouter()
  const { theme, toggleTheme } = useTheme()
  const [activeSection, setActiveSection] = useState<SettingsSection>('account')
  const [loading, setLoading] = useState(true)
  const [user, setUser] = useState<SupabaseUser | null>(null)
  const [profile, setProfile] = useState<Database['public']['Tables']['users']['Row'] | null>(null)
  const [saving, setSaving] = useState(false)
  const [disappearingMessages, setDisappearingMessages] = useState('Off')

  // Local Settings States
  const [compactMode, setCompactMode] = useState(false)
  const [deleteConfirm, setDeleteConfirm] = useState('')

  useEffect(() => {
    const setup = async () => {
      try {
        const { data: { user } } = await supabase.auth.getUser()
        if (!user) {
          router.push('/auth/login')
          return
        }
        setUser(user)

        const { data: prof, error: profError } = await supabase
          .from('users')
          .select('*')
          .eq('id', user.id)
          .maybeSingle()

        if (profError) {
          console.error('Error fetching profile:', profError)
        }

        setProfile(prof || { username: 'anonymous' })
      } catch (err) {
        console.error('Settings setup error:', err)
      } finally {
        setLoading(false)
        const savedCompact = typeof window !== 'undefined' ? localStorage.getItem('appearance_compact') === 'true' : false
        setCompactMode(savedCompact)
        setDisappearingMessages(typeof window !== 'undefined' ? (localStorage.getItem('ag_disappearing_messages') || 'Off') : 'Off')
      }
    }

    setup()
  }, [])

  const updateProfile = async (updates: Partial<Database['public']['Tables']['users']['Row']>) => {
    if (!user) return
    setSaving(true)
    try {
      const { error } = await supabase
        .from('users')
        .update(updates)
        .eq('id', user.id)

      if (error) throw error
      if (profile) setProfile({ ...profile, ...updates })
    } catch (error) {
      console.error('Error updating profile:', error)
      alert('Failed to save settings')
    } finally {
      setSaving(false)
    }
  }

  const toggleCompactMode = () => {
    const newState = !compactMode
    setCompactMode(newState)
    localStorage.setItem('appearance_compact', String(newState))
    window.location.reload()
  }

  const handleLogout = async () => {
    await supabase.auth.signOut()
    router.push('/')
  }

  const handleRegenerateKeys = async () => {
    if (confirm("This will permanently lose access to old messages. New messages will be secure. Continue?")) {
      await resetKeys()
      alert("Keys regenerated successfully!")
    }
  }

  const handleDownloadData = () => {
    if (!user || !profile) return
    const data = {
      profile,
      user: {
        id: user.id,
        email: user.email,
        created_at: user.created_at,
        last_sign_in_at: user.last_sign_in_at
      },
      export_date: new Date().toISOString()
    }
    const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' })
    const url = URL.createObjectURL(blob)
    const a = document.createElement('a')
    a.href = url
    a.download = `argentum_data_${profile.username}.json`
    document.body.appendChild(a)
    a.click()
    document.body.removeChild(a)
    URL.revokeObjectURL(url)
  }

  const handleUpdateDisappearing = (val: string) => {
    setDisappearingMessages(val)
    localStorage.setItem('ag_disappearing_messages', val)
  }

  const handleConnect = async (provider: 'github' | 'google') => {
    try {
      const { data, error } = await supabase.auth.signInWithOAuth({
        provider,
        options: {
          redirectTo: `${window.location.origin}/settings?activeSection=account`,
          skipBrowserRedirect: false
        }
      })
      if (error) throw error
    } catch (error) {
       console.error(`Error connecting ${provider}:`, error)
       alert(`Failed to connect ${provider}`)
    }
  }

  if (loading) {
    return (
      <div className="h-screen bg-background flex items-center justify-center">
        <Loader2 className="w-8 h-8 text-silver animate-spin" />
      </div>
    )
  }

  const sections = [
    { id: 'account', label: 'Account', icon: User },
    { id: 'privacy', label: 'Privacy', icon: Eye },
    { id: 'notifications', label: 'Notifications', icon: Bell },
    { id: 'messaging', label: 'Messaging', icon: MessageSquare },
    { id: 'security', label: 'Security', icon: Shield },
    { id: 'appearance', label: 'Appearance', icon: Layout },
    { id: 'danger', label: 'Danger Zone', icon: ShieldAlert },
