"use client"

import { useState, useRef, useEffect } from 'react'
import { Camera, X, RefreshCw, ChevronRight, Check } from 'lucide-react'

interface CameraCaptureProps {
  isOpen: boolean
  onClose: () => void
  onCapture: (blob: Blob) => void
}

export default function CameraCapture({ isOpen, onClose, onCapture }: CameraCaptureProps) {
  const [stream, setStream] = useState<MediaStream | null>(null)
  const [capturedImage, setCapturedImage] = useState<string | null>(null)
  const [error, setError] = useState<string | null>(null)
  const videoRef = useRef<HTMLVideoElement>(null)
  const canvasRef = useRef<HTMLCanvasElement>(null)

  useEffect(() => {
    if (isOpen) {
      startCamera()
    } else {
      stopCamera()
    }
    return () => stopCamera()
  }, [isOpen])

  const startCamera = async () => {
    try {
      const mediaStream = await navigator.mediaDevices.getUserMedia({ 
        video: { facingMode: 'user' },
        audio: false 
      })
      setStream(mediaStream)
      if (videoRef.current) {
        videoRef.current.srcObject = mediaStream
      }
      setError(null)
    } catch (err) {
      console.error("Camera error:", err)
      setError("Unable to access camera. Please check permissions.")
    }
  }

  const stopCamera = () => {
    if (stream) {
      stream.getTracks().forEach(track => track.stop())
      setStream(null)
    }
    setCapturedImage(null)
  }

  const capturePhoto = () => {
    if (videoRef.current && canvasRef.current) {
      const video = videoRef.current
      const canvas = canvasRef.current
      canvas.width = video.videoWidth
      canvas.height = video.videoHeight
      canvas.getContext('2d')?.drawImage(video, 0, 0)

      const dataUrl = canvas.toDataURL('image/jpeg')
      setCapturedImage(dataUrl)
    }
  }

  const handleConfirm = () => {
    if (capturedImage && canvasRef.current) {
      canvasRef.current.toBlob((blob) => {
        if (blob) onCapture(blob)
        onClose()
      }, 'image/jpeg', 0.8)
    }
  }

  if (!isOpen) return null

  return (
    <div className="fixed inset-0 z-[1000] flex items-center justify-center p-4 bg-black/95 backdrop-blur-xl animate-fade-in">
      <div className="bg-[#050505] border border-white/10 rounded-[3rem] w-full max-w-2xl overflow-hidden shadow-3xl flex flex-col relative aspect-[3/4]">
        <button 
          onClick={onClose} 
          className="absolute top-6 right-6 p-3 bg-black/50 hover:bg-white/10 rounded-full transition-all text-white z-20"
        >
          <X size={20} />
        </button>

        <div className="flex-1 relative bg-black flex items-center justify-center overflow-hidden">
          {error ? (
            <div className="flex flex-col items-center gap-4 text-center px-10">
              <Camera size={48} className="text-gray-800" />
              <p className="text-sm text-gray-500 font-mono uppercase tracking-widest">{error}</p>
              <button onClick={startCamera} className="px-6 py-2 rounded-xl bg-white/5 border border-white/10 text-[10px] font-black uppercase tracking-widest">Retry</button>
            </div>
          ) : capturedImage ? (
            <img src={capturedImage} className="w-full h-full object-cover animate-scale-in" />
          ) : (
            <video ref={videoRef} autoPlay playsInline className="w-full h-full object-cover" />
          )}

          <canvas ref={canvasRef} className="hidden" />

          {/* Overlay Grid */}
          {!capturedImage && !error && (
            <div className="absolute inset-0 pointer-events-none border-[0.5px] border-white/5 grid grid-cols-3 grid-rows-3">
               {Array.from({ length: 9 }).map((_, i) => <div key={i} className="border-[0.5px] border-white/5" />)}
            </div>
          )}
        </div>

        <div className="p-8 bg-[#0a0a0a] flex items-center justify-center gap-8 border-t border-white/5">
          {capturedImage ? (
            <>
              <button 
                onClick={() => setCapturedImage(null)} 
                className="w-16 h-16 rounded-full bg-white/5 border border-white/10 flex items-center justify-center text-gray-400 hover:text-white transition-all hover:bg-white/10"
              >
                <RefreshCw size={24} />
              </button>
              <button 
                onClick={handleConfirm} 
                className="w-20 h-20 rounded-full silver-metallic flex items-center justify-center text-black shadow-glow hover:scale-105 active:scale-95 transition-all"
              >
                <Check size={32} />
              </button>
            </>
          ) : (
            <button 
              onClick={capturePhoto} 
              disabled={!stream}
              className="w-20 h-20 rounded-full border-4 border-white flex items-center justify-center group active:scale-95 transition-all disabled:opacity-50"
            >
              <div className="w-16 h-16 rounded-full bg-white group-hover:scale-90 transition-transform" />
            </button>
          )}
        </div>
      </div>
    </div>
  )
}

"use client"

import { useState, useEffect, useRef } from 'react'
import { motion, AnimatePresence } from 'framer-motion'
import { Search, User, Zap, Hash, ArrowRight, Loader2, X, Command } from 'lucide-react'
import { useRouter } from 'next/navigation'
import { useSearch } from '@/context/SearchContext'
import { createClient } from '@/lib/supabase/client'

export default function CommandPalette() {
  const { isOpen, setIsOpen, query, setQuery } = useSearch()
  const [results, setResults] = useState<{ users: any[], posts: any[] }>({ users: [], posts: [] })
  const [loading, setLoading] = useState(false)
  const [selectedIndex, setSelectedIndex] = useState(0)
  const router = useRouter()
  const supabase = createClient()
  const inputRef = useRef<HTMLInputElement>(null)

  useEffect(() => {
    if (isOpen) {
      inputRef.current?.focus()
      setSelectedIndex(0)
    }
  }, [isOpen])

  useEffect(() => {
    if (!query) {
      setResults({ users: [], posts: [] })
      return
    }

    const fetchResults = async () => {
      setLoading(true)
      const { data: usersData } = await supabase
        .from('users')
        .select('id, username, display_name, avatar_url')
        .or(`username.ilike.%${query}%,display_name.ilike.%${query}%`)
        .limit(4)

      const { data: postsData } = await supabase
        .from('posts')
        .select('id, title, category')
        .or(`title.ilike.%${query}%,content.ilike.%${query}%`)
        .limit(4)

      setResults({ 
        users: usersData || [], 
        posts: postsData || [] 
      })
      setLoading(false)
    }

    const timer = setTimeout(fetchResults, 300)
    return () => clearTimeout(timer)
  }, [query])

  const flattenResults = [
    ...(query ? [{ type: 'search', query }] : []),
    ...results.users.map(u => ({ type: 'user', ...u })),
    ...results.posts.map(p => ({ type: 'post', ...p }))
  ]

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (flattenResults.length === 0) return

    if (e.key === 'ArrowDown') {
      e.preventDefault()
      setSelectedIndex(prev => (prev + 1) % flattenResults.length)
    } else if (e.key === 'ArrowUp') {
      e.preventDefault()
      setSelectedIndex(prev => (prev - 1 + flattenResults.length) % flattenResults.length)
    } else if (e.key === 'Enter') {
      const item = flattenResults[selectedIndex]
      if (!item) return

      if (item.type === 'user') router.push(`/profile/${item.username}`)
      else if (item.type === 'post') router.push(`/post/${item.id}`)
      else if (item.type === 'search') router.push(`/explore?q=${query}`)

      setIsOpen(false)
      setQuery('')
    }
  }

  return (
    <AnimatePresence>
      {isOpen && (
        <div className="fixed inset-0 z-[200] flex items-start justify-center pt-[15vh] px-4">
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            onClick={() => setIsOpen(false)}
            className="absolute inset-0 bg-background/80 backdrop-blur-sm"
          />

          <motion.div
            initial={{ opacity: 0, scale: 0.95, y: -20 }}
            animate={{ opacity: 1, scale: 1, y: 0 }}
            exit={{ opacity: 0, scale: 0.95, y: -20 }}
            className="w-full max-w-2xl bg-card border border-border rounded-3xl shadow-2xl overflow-hidden relative z-10"
          >
            {/* Search Input Area */}
            <div className="flex items-center gap-4 px-6 py-5 border-b border-border bg-foreground/5">
              <Search className="text-foreground/20" size={20} />
              <input
                ref={inputRef}
                type="text"
                placeholder="Search anything on Argentum..."
                value={query}
                onChange={(e) => setQuery(e.target.value)}
                onKeyDown={handleKeyDown}
                className="flex-1 bg-transparent border-none outline-none text-lg text-foreground placeholder:text-foreground/20"
              />
              <div className="flex items-center gap-2">
                {loading && <Loader2 className="animate-spin text-green-500" size={18} />}
                <button 
                  onClick={() => setIsOpen(false)}
                  className="p-1.5 hover:bg-foreground/5 rounded-lg text-foreground/20 hover:text-foreground transition-all"
                >
                  <X size={18} />
                </button>
              </div>
            </div>

            {/* Results Area */}
            <div className="max-h-[60vh] overflow-y-auto p-2 custom-scrollbar">
              {flattenResults.length > 0 ? (
                <div className="flex flex-col gap-1">
                  {/* Global Search Option */}
                  {query && (
                    <ResultItem 
                      icon={<Search size={16} />}
                      title={`Search everything for "${query}"`}
                      subtitle="Open global results in Explore"
                      active={selectedIndex === 0}
                      onClick={() => { router.push(`/explore?q=${query}`); setIsOpen(false); setQuery(''); }}
                    />
                  )}

                  {results.users.length > 0 && (
                    <div className="px-4 py-2 mt-2 border-t border-white/5">
                      <span className="text-[10px] font-black text-white/20 uppercase tracking-[0.3em]">Builders</span>
                    </div>
                  )}
                  {results.users.map((user, i) => (
                    <ResultItem 
                      key={user.id}
                      icon={<User size={16} />}
                      title={user.display_name || user.username}
                      subtitle={`@${user.username}`}
                      active={selectedIndex === (query ? i + 1 : i)}
                      onClick={() => { router.push(`/profile/${user.username}`); setIsOpen(false); setQuery(''); }}
                    />
                  ))}

                  {results.posts.length > 0 && (
                    <div className="px-4 py-2 mt-4 border-t border-white/5">
                      <span className="text-[10px] font-black text-white/20 uppercase tracking-[0.3em]">Builds</span>
                    </div>
                  )}
                  {results.posts.map((post, i) => (
                    <ResultItem 
                      key={post.id}
                      icon={<Zap size={16} />}
                      title={post.title}
                      subtitle={`in #${post.category || 'all'}`}
                      active={selectedIndex === (query ? i + 1 + results.users.length : i + results.users.length)}
                      onClick={() => { router.push(`/post/${post.id}`); setIsOpen(false); setQuery(''); }}
                    />
                  ))}
                </div>
              ) : query ? (
                <div className="p-8 text-center flex flex-col items-center gap-4">
                  <div className="text-white/10">
                    <Hash size={40} />
                  </div>
                  <p className="text-gray-500 text-sm">No direct hits for "{query}"</p>
                  <button 
                    onClick={() => { router.push(`/explore?q=${query}`); setIsOpen(false); }}
                    className="flex items-center gap-2 px-6 py-2 rounded-full border border-white/10 text-[10px] font-black uppercase tracking-widest hover:bg-white/5 transition-all"
                  >
                    View global results <ArrowRight size={14} />
                  </button>
                </div>
              ) : (
                <div className="p-12 text-center">
                  <div className="w-16 h-16 rounded-2xl border border-white/5 bg-white/[0.02] flex items-center justify-center mx-auto mb-6">
                    <Command className="text-white/20" size={32} />
                  </div>
                  <h3 className="text-white font-bold mb-2">Command Palette</h3>
                  <p className="text-gray-500 text-sm max-w-xs mx-auto">
                    Type to find builders, specific builds, or explore the network.
                  </p>

                  <div className="mt-8 flex flex-wrap justify-center gap-2">
                    {['#Web3', '#AI', '#Solana', '#Argentum'].map(tag => (
                      <button 
                        key={tag}
                        onClick={() => setQuery(tag.replace('#', ''))}
                        className="px-4 py-1.5 rounded-full bg-foreground/5 border border-border text-[10px] font-bold text-foreground/40 hover:text-foreground hover:border-foreground/20 transition-all"
                      >
                        {tag}
                      </button>
                    ))}
                  </div>
                </div>
              )}
            </div>

            {/* Footer */}
            <div className="px-6 py-3 border-t border-border flex items-center justify-between text-[10px] font-mono text-foreground/20 bg-foreground/[0.02]">
              <div className="flex items-center gap-4">
                <span className="flex items-center gap-1.5"><kbd className="px-1.5 py-0.5 rounded bg-foreground/5 border border-border">↑↓</kbd> to navigate</span>
                <span className="flex items-center gap-1.5"><kbd className="px-1.5 py-0.5 rounded bg-foreground/5 border border-border">↵</kbd> to select</span>
              </div>
              <div className="flex items-center gap-1.5">
                <kbd className="px-1.5 py-0.5 rounded bg-foreground/5 border border-border">ESC</kbd> to close
              </div>
            </div>
          </motion.div>
        </div>
      )}
    </AnimatePresence>
  )
}

function ResultItem({ icon, title, subtitle, active, onClick }: any) {
  return (
    <div 
      onClick={onClick}
      className={`
        flex items-center gap-4 px-4 py-3 rounded-2xl cursor-pointer transition-all
        ${active ? 'bg-foreground/10 translate-x-1' : 'hover:bg-foreground/5'}
      `}
    >
      <div className={`
        w-10 h-10 rounded-xl flex items-center justify-center border transition-all
        ${active ? 'border-green-500 bg-green-500 text-black shadow-xl' : 'border-border bg-foreground/5 text-foreground/40'}
      `}>
        {icon}
      </div>
      <div className="flex flex-col min-w-0">
        <span className={`text-sm font-bold transition-colors ${active ? 'text-background' : 'text-foreground/60'}`}>{title}</span>
        <span className="text-[10px] text-foreground/20 font-medium truncate">{subtitle}</span>
      </div>
      {active && (
        <div className="ml-auto text-green-500">
          <ArrowRight size={14} />
        </div>
      )}
    </div>
  )
}

"use client"

import { useState, useEffect } from 'react'
import { createClient } from '@/lib/supabase/client'
import { MessageCircle, Heart, Reply, Trash2, Flag, SortAsc, SortDesc, User, MoreVertical, CheckCircle2, Loader2, AlertTriangle } from 'lucide-react'
import Link from 'next/link'

interface Comment {
  id: string
  content: string
  user_id: string
  created_at: string
  users: {
    username: string
    display_name: string
    avatar_url: string
    skills: string[]
  }
  likes_count?: number
  is_liked?: boolean
}

interface CommentsSectionProps {
  postId: string
  postOwnerId: string
  currentUserId?: string
}

export default function CommentsSection({ postId, postOwnerId, currentUserId }: CommentsSectionProps) {
  const supabase = createClient()
  const [comments, setComments] = useState<Comment[]>([])
  const [newComment, setNewComment] = useState('')
  const [replyTo, setReplyTo] = useState<Comment | null>(null)
  const [sortBy, setSortBy] = useState<'newest' | 'oldest' | 'liked'>('newest')
  const [loading, setLoading] = useState(true)
  const [submitting, setSubmitting] = useState(false)

  useEffect(() => {
    fetchComments()
  }, [postId, sortBy])

  const fetchComments = async () => {
    setLoading(true)
    let query = supabase
      .from('comments')
      .select('*, users(username, display_name, avatar_url, skills)')
      .eq('post_id', postId)

    if (sortBy === 'oldest') {
      query = query.order('created_at', { ascending: true })
    } else {
      query = query.order('created_at', { ascending: false })
    }

    const { data, error } = await query
    if (data) {
      // Fetch likes count for each comment (mocking for now as table might not exist yet)
      setComments(data as any)
    }
    setLoading(false)
  }

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault()
    if (!newComment.trim() || !currentUserId) return

    setSubmitting(true)
    let finalContent = newComment
    if (replyTo) {
      finalContent = `> @${replyTo.users.username}: ${replyTo.content.slice(0, 50)}${replyTo.content.length > 50 ? '...' : ''}\n\n${newComment}`
    }

    const { data, error } = await supabase
      .from('comments')
      .insert({
        post_id: postId,
        user_id: currentUserId,
        content: finalContent
      })
      .select('*, users(username, display_name, avatar_url, skills)')
      .single()

    if (data) {
      setComments([data as any, ...comments])
      setNewComment('')
      setReplyTo(null)

      // Notify post owner
      if (postOwnerId !== currentUserId) {
        await supabase.from('notifications').insert({
          user_id: postOwnerId,
          from_user_id: currentUserId,
          type: 'comment',
          content: `Someone commented on your build`,
          link: `/post/${postId}`
        })
      }
    }
    setSubmitting(false)
  }

  const handleDelete = async (id: string) => {
    if (!confirm('Delete this comment?')) return
    const { error } = await supabase.from('comments').delete().eq('id', id)
    if (!error) {
      setComments(comments.filter(c => c.id !== id))
    }
  }

  return (
    <div className="flex flex-col gap-8 mt-12">
      <div className="flex items-center justify-between border-b border-border pb-4">
        <h3 className="text-xl font-black uppercase tracking-tighter flex items-center gap-2">
          <MessageCircle size={20} className="text-foreground/40" />
          Comments ({comments.length})
        </h3>

        <div className="flex items-center gap-4">
          <select 
            value={sortBy} 
            onChange={(e: any) => setSortBy(e.target.value)}
            className="bg-transparent text-[10px] font-black uppercase tracking-widest text-foreground/40 hover:text-foreground cursor-pointer outline-none"
          >
            <option value="newest">Newest First</option>
            <option value="oldest">Oldest First</option>
            <option value="liked">Most Liked</option>
          </select>
        </div>
      </div>

      {currentUserId ? (
        <form onSubmit={handleSubmit} className="flex flex-col gap-4">
          {replyTo && (
            <div className="flex items-center justify-between p-3 rounded-xl bg-card border border-border animate-fade-in">
              <span className="text-xs text-foreground/40">Replying to @{replyTo.users.username}</span>
              <button type="button" onClick={() => setReplyTo(null)} className="text-foreground/40 hover:text-foreground"><X size={14}/></button>
            </div>
          )}
          <div className="relative">
            <textarea
              value={newComment}
              onChange={(e) => setNewComment(e.target.value)}
              placeholder="What do you think about this build?"
              className="w-full bg-background border border-border rounded-2xl p-6 text-sm focus:outline-none focus:border-foreground/30 transition-all min-h-[120px] resize-none"
            />
            <button
              type="submit"
              disabled={!newComment.trim() || submitting}
              className="absolute bottom-4 right-4 silver-metallic px-6 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest hover:brightness-110 active:scale-95 transition-all disabled:opacity-50"
            >
              {submitting ? <Loader2 size={14} className="animate-spin" /> : 'Post Comment'}
            </button>
          </div>
        </form>
      ) : (
        <div className="glass-card p-8 flex flex-col items-center gap-4 border-dashed">
          <p className="text-sm text-foreground/40">You must be logged in to participate in the discussion.</p>
          <Link href="/auth/login" className="px-8 py-3 rounded-xl bg-foreground/5 border border-border text-[10px] font-black uppercase tracking-[0.2em] hover:bg-foreground/10">Sign In</Link>
        </div>
      )}

      <div className="flex flex-col gap-6">
        {loading ? (
          <div className="flex flex-col items-center py-20 gap-4">
            <Loader2 size={24} className="animate-spin text-foreground/40" />
            <span className="text-[10px] font-black text-foreground/20 uppercase tracking-widest">Retrieving logs...</span>
          </div>
        ) : comments.length === 0 ? (
          <div className="py-20 text-center flex flex-col items-center gap-4 text-foreground/20 font-mono text-xs uppercase tracking-widest">
            Be the first to comment on this build.
          </div>
        ) : (
          comments.map((comment, i) => (
            <div 
              key={comment.id} 
              className="glass-card p-6 flex flex-col gap-4 group animate-fade-in-up"
              style={{ animationDelay: `${i * 50}ms` }}
            >
              <div className="flex items-center justify-between">
                <div className="flex items-center gap-3">
                  <div className="w-10 h-10 rounded-xl bg-background border border-border flex items-center justify-center overflow-hidden">
                    {comment.users.avatar_url ? (
                      <img src={comment.users.avatar_url} className="w-full h-full object-cover" />
                    ) : (
                      <span className="text-sm font-black">{comment.users.username?.[0]?.toUpperCase()}</span>
                    )}
                  </div>
                  <div className="flex flex-col">
                    <div className="flex items-center gap-2">
                      <span className="font-bold text-foreground text-sm">{comment.users.display_name || comment.users.username}</span>
                      {comment.user_id === postOwnerId && (
                        <span className="px-1.5 py-0.5 rounded-md bg-green-500/10 border border-green-500/20 text-[8px] font-black uppercase tracking-widest text-green-500">Author</span>
                      )}
                      {comment.users.skills?.slice(0, 2).map(skill => (
                        <span key={skill} className="px-1.5 py-0.5 rounded-md bg-foreground/5 border border-border text-[8px] font-bold text-foreground/40 uppercase tracking-tighter">
                          {skill}
                        </span>
                      ))}
                    </div>
                    <span className="text-[10px] text-foreground/40 font-mono">@{comment.users.username} • {new Date(comment.created_at).toLocaleDateString()}</span>
                  </div>
                </div>

                <div className="flex items-center gap-2">
                  {comment.user_id === currentUserId && (
                    <button onClick={() => handleDelete(comment.id)} className="p-2 text-foreground/20 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-all">
                      <Trash2 size={14} />
                    </button>
                  )}
                  <button className="p-2 text-foreground/20 hover:text-foreground opacity-0 group-hover:opacity-100 transition-all">
                    <MoreVertical size={14} />
                  </button>
                </div>
              </div>

               <div className="text-sm text-foreground/80 leading-relaxed whitespace-pre-wrap pl-13">
                {comment.content}
              </div>

              <div className="flex items-center gap-6 pl-13">
                <button className="flex items-center gap-1.5 text-[10px] font-bold text-foreground/40 hover:text-red-500 transition-all">
                  <Heart size={14} />
                  <span>0</span>
                </button>
                <button onClick={() => { setReplyTo(comment); window.scrollTo({ top: 0, behavior: 'smooth' }); }} className="flex items-center gap-1.5 text-[10px] font-bold text-foreground/40 hover:text-foreground transition-all">
                  <Reply size={14} />
                  <span>Reply</span>
                </button>
                <button className="flex items-center gap-1.5 text-[10px] font-bold text-foreground/40 hover:text-foreground opacity-0 group-hover:opacity-100 transition-all ml-auto">
                  <Flag size={14} />
                  <span>Report</span>
                </button>
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  )
}

function X({ size }: { size: number }) {
