            </div>
            No data found in sector: {selectedCategory}
          </div>
        )}
      </div>
    </div>
  )
}

"use client"

import { useState, useEffect, useRef, useCallback } from 'react'
import { X, Search, Loader2, UserCircle2 } from 'lucide-react'
import { createClient } from '@/lib/supabase/client'
import Link from 'next/link'
import { getGradientFromUsername, getInitials } from '@/lib/utils/ui'
import FollowButton from './FollowButton'
import { motion, AnimatePresence } from 'framer-motion'
import { Database } from '@/types/database'

type UserProfile = Database['public']['Tables']['users']['Row']

interface FollowListModalProps {
  isOpen: boolean
  onClose: () => void
  userId: string
  username: string
  initialTab: 'followers' | 'following'
}

export default function FollowListModal({ isOpen, onClose, userId, username, initialTab }: FollowListModalProps) {
  const [activeTab, setActiveTab] = useState(initialTab)
  const [searchQuery, setSearchQuery] = useState('')
  const [users, setUsers] = useState<UserProfile[]>([])
  const [loading, setLoading] = useState(false)
  const [hasMore, setHasMore] = useState(true)
  const [page, setPage] = useState(0)
  const [totalCount, setTotalCount] = useState(0)
  const observer = useRef<IntersectionObserver | null>(null)
  const lastUserRef = useCallback((node: HTMLElement | null) => {
    if (loading) return
    if (observer.current) observer.current.disconnect()
    observer.current = new IntersectionObserver(entries => {
      if (entries[0].isIntersecting && hasMore) {
        setPage(prevPage => prevPage + 1)
      }
    })
    if (node) observer.current.observe(node)
  }, [loading, hasMore])

  const supabase = createClient()

  const fetchUsers = async (reset = false) => {
    setLoading(true)
    const currentPage = reset ? 0 : page
    const start = currentPage * 20
    const end = start + 19

    try {
      let query;
      if (activeTab === 'followers') {
        query = supabase
          .from('follows')
          .select('id, follower:follower_id(*)', { count: 'exact' })
          .eq('following_id', userId)
          .range(start, end)
      } else {
        query = supabase
          .from('follows')
          .select('id, following:following_id(*)', { count: 'exact' })
          .eq('follower_id', userId)
          .range(start, end)
      }

      const { data, count, error } = await query as { data: any[] | null, count: number | null, error: any }

      if (error) throw error

      const formattedUsers = data?.map((item) => activeTab === 'followers' ? item.follower : item.following) || []

      const filteredUsers = formattedUsers.filter((u: UserProfile) => 
        u.username.toLowerCase().includes(searchQuery.toLowerCase()) || 
        (u.display_name && u.display_name.toLowerCase().includes(searchQuery.toLowerCase()))
      )

      if (reset) {
        setUsers(filteredUsers)
      } else {
        setUsers(prev => [...prev, ...filteredUsers])
      }

      setTotalCount(count || 0)
      setHasMore(formattedUsers.length === 20)
    } catch (err) {
      console.error('Error fetching users:', err)
    } finally {
      setLoading(false)
    }
  }

  useEffect(() => {
    if (isOpen) {
      setPage(0)
      setHasMore(true)
      fetchUsers(true)
    }
  }, [isOpen, activeTab, userId])

  useEffect(() => {
    if (page > 0) {
      fetchUsers()
    }
  }, [page])

  // Simple client-side search for the current loaded list, but ideally we'd search the DB
  // For now, let's keep it simple or implement a debounce for DB search
  useEffect(() => {
    const timer = setTimeout(() => {
      if (isOpen) {
        setPage(0)
        fetchUsers(true)
      }
    }, 300)
    return () => clearTimeout(timer)
  }, [searchQuery])

  if (!isOpen) return null

  return (
    <AnimatePresence>
      <div className="fixed inset-0 z-[60] flex items-center justify-center p-4">
        <motion.div 
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          exit={{ opacity: 0 }}
          onClick={onClose}
          className="absolute inset-0 bg-background/80 backdrop-blur-sm" 
        />

        <motion.div 
          initial={{ opacity: 0, scale: 0.95, y: 20 }}
          animate={{ opacity: 1, scale: 1, y: 0 }}
          exit={{ opacity: 0, scale: 0.95, y: 20 }}
          className="relative w-full max-w-md bg-card border border-border rounded-2xl overflow-hidden shadow-2xl flex flex-col max-h-[80vh]"
        >
          {/* Header */}
          <div className="p-4 border-b border-border flex items-center justify-between bg-foreground/5">
            <h3 className="font-bold text-foreground uppercase tracking-widest text-xs">
              {activeTab === 'followers' ? `Followers (${totalCount})` : `Following (${totalCount})`}
            </h3>
            <button onClick={onClose} className="p-1 hover:bg-foreground/5 rounded-lg transition-colors">
              <X size={18} className="text-foreground/40" />
            </button>
          </div>

          {/* Tabs */}
          <div className="flex border-b border-border">
            <button 
              onClick={() => setActiveTab('followers')}
              className={`flex-1 py-3 text-[10px] font-black uppercase tracking-widest transition-all ${activeTab === 'followers' ? 'text-foreground border-b-2 border-foreground bg-foreground/5' : 'text-foreground/40 hover:text-foreground'}`}
            >
              Followers
            </button>
            <button 
              onClick={() => setActiveTab('following')}
              className={`flex-1 py-3 text-[10px] font-black uppercase tracking-widest transition-all ${activeTab === 'following' ? 'text-foreground border-b-2 border-foreground bg-foreground/5' : 'text-foreground/40 hover:text-foreground'}`}
            >
              Following
            </button>
          </div>

          {/* Search */}
          <div className="p-4 relative">
            <Search className="absolute left-7 top-1/2 -translate-y-1/2 text-foreground/40" size={14} />
            <input 
              type="text"
              placeholder="Search users..."
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="w-full bg-foreground/5 border border-border rounded-xl py-2 pl-10 pr-4 text-xs text-foreground placeholder:text-foreground/40 focus:outline-none focus:border-foreground/20 transition-all"
            />
          </div>

          {/* User List */}
          <div className="flex-1 overflow-y-auto p-2 space-y-1 custom-scrollbar">
            {users.length > 0 ? (
              users.map((user, index) => (
                <div 
                  key={user.id}
                  ref={index === users.length - 1 ? lastUserRef : null}
                  className="p-3 flex items-center justify-between hover:bg-foreground/5 rounded-xl transition-all group"
                >
                  <Link 
                    href={`/profile/${user.username}`}
                    onClick={onClose}
                    className="flex items-center gap-3 overflow-hidden flex-1"
                  >
                    <div 
                      className="w-10 h-10 rounded-full shrink-0 flex items-center justify-center border border-border"
                      style={{ background: getGradientFromUsername(user.username) }}
                    >
                      {user.avatar_url ? (
                        <img src={user.avatar_url} alt={user.username} className="w-full h-full object-cover rounded-full" />
                      ) : (
                        <span className="text-xs font-black text-foreground">{getInitials(user.display_name, user.username)}</span>
                      )}
                    </div>
                    <div className="flex flex-col overflow-hidden">
                      <div className="flex items-center gap-1.5">
                        <span className="text-xs font-bold text-foreground truncate">{user.display_name || user.username}</span>
                      </div>
                      <span className="text-[10px] text-foreground/40 truncate">@{user.username}</span>
                      {user.bio && (
                        <p className="text-[10px] text-foreground/20 truncate mt-0.5">{user.bio}</p>
                      )}
                      {user.skills && user.skills.length > 0 && (
                        <div className="flex gap-1 mt-1">
                          {user.skills.slice(0, 2).map((skill: string) => (
                            <span key={skill} className="px-1.5 py-0.5 bg-foreground/5 border border-border rounded text-[8px] text-foreground/40 capitalize whitespace-nowrap">
                              {skill}
                            </span>
                          ))}
                        </div>
                      )}
                    </div>
                  </Link>

                  <FollowButton 
                    followingId={user.id}
                    initialIsFollowing={true} // This is slightly tricky, we'd need to know if the CURRENT user follows this user
                    // For the "Following" tab, it's true if we are looking at OUR OWN following list.
                    // But if we are looking at someone else's list, we don't know.
                    // Let's rely on FollowButton's internal state which usually fetches or is passed.
                    className="px-4 py-1.5 !rounded-xl"
                  />
                </div>
              ))
            ) : loading ? (
              <div className="flex flex-col items-center justify-center py-12 gap-3 opacity-20">
                <Loader2 size={32} className="animate-spin" />
              </div>
            ) : (
              <div className="flex flex-col items-center justify-center py-12 text-center opacity-30">
                <div className="w-12 h-12 rounded-2xl bg-foreground/5 border border-border flex items-center justify-center mb-4">
                  <UserCircle2 size={24} className="text-foreground" />
                </div>
                <p className="text-xs font-black text-foreground uppercase tracking-widest">
                  {activeTab === 'followers' ? 'No followers yet' : 'Not following anyone yet'}
                </p>
              </div>
            )}
            {loading && users.length > 0 && (
              <div className="py-4 flex justify-center">
                <Loader2 size={16} className="animate-spin text-gray-600" />
              </div>
            )}
          </div>
        </motion.div>
      </div>
    </AnimatePresence>
  )
}

"use client"

import { useState, useEffect } from 'react'
import { createClient } from '@/lib/supabase/client'
import PostCard from './PostCard'
import { Loader2 } from 'lucide-react'
import ReportModal from './ReportModal'

interface InfiniteFeedProps {
  initialPosts: any[]
  category: string
}

export default function InfiniteFeed({ initialPosts, category }: InfiniteFeedProps) {
  const [posts, setPosts] = useState(initialPosts)
  const [loading, setLoading] = useState(false)
  const [hasMore, setHasMore] = useState(initialPosts.length === 10)
  const [page, setPage] = useState(1)
  const [currentUserId, setCurrentUserId] = useState<string | null>(null)
  const [reportingPostId, setReportingPostId] = useState<string | null>(null)
  const supabase = createClient()

  useEffect(() => {
    supabase.auth.getUser().then(({ data: { user } }: any) => {
      if (user) setCurrentUserId(user.id)
    })
  }, [])

  useEffect(() => {
    setPosts(initialPosts)
    setPage(1)
    setHasMore(initialPosts.length === 10)
  }, [initialPosts])

  const loadMore = async () => {
    if (loading || !hasMore) return
    setLoading(true)

    const start = page * 10
    const end = start + 9

    let query = supabase
      .from('posts')
      .select('*, users(id, username, display_name, avatar_url, bio, currently_building)')
      .eq('status', 'published')
      .order('created_at', { ascending: false })
      .range(start, end)

    if (category !== 'All') {
      query = query.eq('category', category)
    }

    const { data, error } = await query

    if (error) {
      console.error('Error loading more posts:', error)
    } else {
      if (data && data.length > 0) {
        setPosts([...posts, ...data])
        setPage(page + 1)
        setHasMore(data.length === 10)
      } else {
        setHasMore(false)
      }
    }
    setLoading(true) // Artificially keep loading for a bit for smooth UI
    setTimeout(() => setLoading(false), 500)
  }

  return (
    <div className="flex flex-col gap-10">
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {posts.map((post) => (
          <PostCard 
            key={post.id} 
            post={post} 
            currentUserId={currentUserId || undefined}
            onReport={(id) => setReportingPostId(id)}
          />
        ))}
      </div>

      <ReportModal 
        isOpen={!!reportingPostId} 
        onClose={() => setReportingPostId(null)}
        postId={reportingPostId || ''}
        currentUserId={currentUserId || ''}
      />

      {hasMore && (
        <div className="flex justify-center pt-8">
          <button
            onClick={loadMore}
            disabled={loading}
            className="px-8 py-3 rounded-xl bg-card border border-border text-xs font-bold uppercase tracking-widest text-foreground/60 hover:bg-foreground/5 hover:border-border/50 transition-all flex items-center gap-2 disabled:opacity-50"
          >
            {loading ? (
              <>
                <Loader2 size={14} className="animate-spin" />
                <span>Synchronizing...</span>
              </>
            ) : (
              <span>Load More Builds</span>
            )}
          </button>
        </div>
      )}

      {!hasMore && posts.length > 0 && (
        <div className="text-center py-10">
            <span className="text-[10px] font-bold text-foreground/20 uppercase tracking-[0.3em]">End of Transmission</span>
        </div>
      )}

      {posts.length === 0 && (
        <div className="py-20 text-center flex flex-col items-center gap-4 animate-fade-in text-foreground/40 font-mono text-sm uppercase tracking-widest">
          <div className="w-12 h-12 rounded-full border border-border flex items-center justify-center opacity-20">
              //
          </div>
          No data found in sector: {category}
        </div>
      )}
    </div>
  )
}

"use client"

import { useState, useEffect } from 'react'
import { motion, AnimatePresence } from 'framer-motion'
import { 
  Shield, 
  Key, 
  FileJson, 
  X, 
  ChevronRight, 
  Lock, 
  ShieldCheck, 
  AlertTriangle,
  Download,
  CheckCircle2,
  ArrowLeft
} from 'lucide-react'
import { createClient } from '@/lib/supabase/client'
import { getStoredSecretKey, encryptPrivateKey } from '@/lib/crypto'

interface KeyBackupModalProps {
  isOpen: boolean
  onClose: () => void
  onSuccess?: () => void
  isSettingsMode?: boolean
}

type Step = 'choose' | 'pin' | 'password' | 'export' | 'success'

export default function KeyBackupModal({ isOpen, onClose, onSuccess, isSettingsMode }: KeyBackupModalProps) {
  const [step, setStep] = useState<Step>('choose')
  const [pin, setPin] = useState(['', '', '', '', '', ''])
  const [confirmPin, setConfirmPin] = useState(['', '', '', '', '', ''])
  const [isConfirming, setIsConfirming] = useState(false)
  const [password, setPassword] = useState('')
  const [confirmPassword, setConfirmPassword] = useState('')
  const [hint, setHint] = useState('')
  const [isLoading, setIsLoading] = useState(false)
  const [error, setError] = useState<string | null>(null)
  const supabase = createClient()

  useEffect(() => {
    if (!isOpen) {
      setStep('choose')
      setPin(['', '', '', '', '', ''])
      setConfirmPin(['', '', '', '', '', ''])
      setIsConfirming(false)
      setPassword('')
      setConfirmPassword('')
      setHint('')
      setError(null)
    }
  }, [isOpen])

  const handleBack = () => {
    if (isConfirming) setIsConfirming(false)
    else setStep('choose')
    setError(null)
  }

  const handlePinChange = (val: string, index: number, isConfirm: boolean) => {
    const newPin = [...(isConfirm ? confirmPin : pin)]
    if (val.length <= 1 && /^\d*$/.test(val)) {
      newPin[index] = val
      if (isConfirm) setConfirmPin(newPin)
      else setPin(newPin)

      // Auto-focus next
      if (val && index < 5) {
        const nextInput = document.getElementById(`pin-${isConfirm ? 'confirm-' : ''}${index + 1}`)
        nextInput?.focus()
      }
    }
  }

  const getPasswordStrength = (p: string) => {
    if (!p) return 0
    let score = 0
    if (p.length >= 8) score++
    if (/[A-Z]/.test(p)) score++
    if (/[0-9]/.test(p)) score++
    if (/[^A-Za-z0-9]/.test(p)) score++
    return score
  }

  const handleBackup = async (method: 'password' | 'exported', secret: string) => {
    setIsLoading(true)
    setError(null)
    try {
      const privateKey = getStoredSecretKey()
      if (!privateKey) throw new Error('Private key not found on this device')

      const encrypted = await encryptPrivateKey(privateKey, secret)

      const { data: { user } } = await supabase.auth.getUser()
      if (!user) throw new Error('Not authenticated')

      const { error: updateError } = await supabase
        .from('users')
        .update({
          encrypted_private_key: encrypted,
          key_backup_method: method,
          key_backup_hint: hint || null,
          key_backup_created_at: new Date().toISOString()
        })
        .eq('id', user.id)

      if (updateError) throw updateError

      setStep('success')
      onSuccess?.()
    } catch (err: any) {
      console.error('Backup failed:', err)
      setError(err.message || 'Failed to create backup')
    } finally {
      setIsLoading(false)
    }
  }

  const handleDownloadBackup = async () => {
    if (password !== confirmPassword) {
      setError('Passwords do not match')
      return
    }
    if (getPasswordStrength(password) < 2) {
      setError('Password is too weak')
      return
    }

    setIsLoading(true)
    try {
      const privateKey = getStoredSecretKey()
      if (!privateKey) throw new Error('Private key not found')

      const encrypted = await encryptPrivateKey(privateKey, password)
      const { data: { user } } = await supabase.auth.getUser()

      const backupData = {
        version: 1,
        created_at: new Date().toISOString(),
        username: user?.email?.split('@')[0],
        encrypted_key: encrypted,
        hint: hint || null
      }

      const blob = new Blob([JSON.stringify(backupData, null, 2)], { type: 'application/json' })
      const url = URL.createObjectURL(blob)
      const link = document.createElement('a')
      link.href = url
      link.download = `argentum-key-backup-${new Date().getTime()}.json`
      document.body.appendChild(link)
      link.click()
      document.body.removeChild(link)
      URL.revokeObjectURL(url)

      await handleBackup('exported', password)
    } catch (err: any) {
      setError(err.message)
    } finally {
      setIsLoading(false)
    }
  }

  const handlePinSubmit = () => {
    if (!isConfirming) {
      if (pin.some(d => !d)) return
      setIsConfirming(true)
    } else {
      if (pin.join('') !== confirmPin.join('')) {
        setError('PINs do not match')
        setConfirmPin(['', '', '', '', '', ''])
        return
      }
      handleBackup('password', pin.join(''))
    }
  }

  const handlePasswordSubmit = () => {
    if (password !== confirmPassword) {
        setError('Passwords do not match')
        return
    }
    handleBackup('password', password)
  }

  return (
    <AnimatePresence>
      {isOpen && (
        <div className="fixed inset-0 z-[1000] flex items-center justify-center px-4">
          <motion.div 
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            onClick={onClose}
            className="absolute inset-0 bg-background/80 backdrop-blur-sm"
          />

          <motion.div
            initial={{ opacity: 0, scale: 0.95, y: 20 }}
            animate={{ opacity: 1, scale: 1, y: 0 }}
            exit={{ opacity: 0, scale: 0.95, y: 20 }}
            className="relative w-full max-w-lg bg-card border border-border rounded-[2.5rem] overflow-hidden shadow-2xl"
          >
            <div className="p-8">
              <div className="flex items-center justify-between mb-8">
                {step !== 'choose' && step !== 'success' && (
                  <button onClick={handleBack} className="p-2 hover:bg-foreground/5 rounded-full transition-all">
                    <ArrowLeft size={20} className="text-foreground/40" />
                  </button>
                )}
                <div className="flex-1 text-center">
                   <h2 className="text-xl font-black tracking-tight text-foreground italic">Argentum Shield</h2>
                </div>
                {!isSettingsMode && step !== 'success' && (
                  <button onClick={onClose} className="p-2 hover:bg-foreground/5 rounded-full transition-all">
                    <X size={20} className="text-foreground/40" />
                  </button>
                )}
              </div>

              {step === 'choose' && (
                <div className="space-y-6">
                  <div className="text-center mb-8">
                    <h3 className="text-2xl font-black mb-2 text-foreground">Back up your messages</h3>
                    <p className="text-sm text-foreground/40 max-w-xs mx-auto">
                      Your keys are only stored on this device. Create a backup to avoid losing your messages forever.
                    </p>
                  </div>

                  <div className="grid gap-3">
                    <MethodCard 
                      icon={<Shield className="text-foreground shrink-0" />} 
                      title="PIN Backup" 
                      desc="Simple recovery for daily use" 
                      badge="Recommended"
                      onClick={() => setStep('pin')}
                    />
                    <MethodCard 
                      icon={<Key className="text-foreground/40 shrink-0" />} 
                      title="Custom Password" 
                      desc="Maximum security for your vault" 
                      onClick={() => setStep('password')}
                    />
                    <MethodCard 
                      icon={<FileJson className="text-foreground/40 shrink-0" />} 
                      title="Export Backup File" 
                      desc="Download and store it yourself" 
                      onClick={() => setStep('export')}
                    />
                    {!isSettingsMode && (
                      <button 
                        onClick={onClose}
                        className="w-full p-6 mt-4 rounded-3xl border border-red-500/20 bg-red-500/5 group hover:bg-red-500/10 transition-all text-left"
                      >
                         <div className="flex items-center gap-3">
                            <AlertTriangle size={20} className="text-red-500 shrink-0" />
                            <div>
                               <h4 className="text-sm font-bold text-red-500 uppercase tracking-widest">Skip for now</h4>
                               <p className="text-[10px] text-red-500/60 font-medium">You will lose access if you lose this device.</p>
                            </div>
                         </div>
                      </button>
                    )}
                  </div>
                </div>
              )}

              {step === 'pin' && (
                <div className="space-y-8 py-4">
                  <div className="text-center">
                    <div className="w-16 h-16 rounded-3xl bg-foreground/5 border border-border flex items-center justify-center mx-auto mb-6 scale-animation">
                      <Lock size={32} className="text-foreground" />
                    </div>
                    <h3 className="text-2xl font-black mb-2 text-foreground">{isConfirming ? 'Confirm your PIN' : 'Set a backup PIN'}</h3>
                    <p className="text-sm text-foreground/40">6 digits to restore your identity</p>
                  </div>

                  <div className="flex justify-center gap-3">
                    {[0,1,2,3,4,5].map(i => (
                      <input
                        key={i}
                        id={`pin-${isConfirming ? 'confirm-' : ''}${i}`}
                        type="password"
                        inputMode="numeric"
                        maxLength={1}
                        value={isConfirming ? confirmPin[i] : pin[i]}
                        onChange={(e) => handlePinChange(e.target.value, i, isConfirming)}
                        className="w-12 h-16 bg-background border border-border rounded-2xl text-center text-2xl font-black text-foreground focus:border-foreground/40 focus:ring-4 focus:ring-foreground/5 outline-none transition-all"
                      />
                    ))}
                  </div>

                  {!isConfirming && (
                    <div className="space-y-2">
                       <label className="text-[10px] font-black uppercase tracking-widest text-foreground/20 ml-4">Backup Hint (Optional)</label>
                       <input 
                         type="text"
                         placeholder="e.g. Grandma's birthday"
                         value={hint}
                         onChange={(e) => setHint(e.target.value)}
                         className="w-full p-5 bg-background border border-border rounded-3xl text-sm focus:border-foreground/40 transition-all"
                       />
                    </div>
                  )}

                  {error && (
                    <p className="text-red-500 text-xs text-center font-bold uppercase tracking-widest">{error}</p>
                  )}

                  <button
                    onClick={handlePinSubmit}
                    disabled={isLoading || (isConfirming ? confirmPin.some(d => !d) : pin.some(d => !d))}
                    className="w-full py-5 bg-foreground text-background rounded-3xl font-black uppercase tracking-widest text-xs disabled:opacity-50 transition-all shadow-xl"
                  >
                    {isLoading ? 'Encrypting...' : isConfirming ? 'Confirm & Protect' : 'Next Step'}
                  </button>
                </div>
              )}

              {step === 'password' && (
                <div className="space-y-8 py-4">
                  <div className="text-center">
                    <div className="w-16 h-16 rounded-3xl bg-foreground/5 border border-border flex items-center justify-center mx-auto mb-6">
                      <Key size={32} className="text-foreground" />
                    </div>
                    <h3 className="text-2xl font-black mb-2 text-foreground">Custom Password</h3>
                    <p className="text-sm text-foreground/40">Use a phrase only you know</p>
                  </div>

                  <div className="grid gap-6">
                    <div className="space-y-2">
                       <label className="text-[10px] font-black uppercase tracking-widest text-foreground/20 ml-4">Enter Password</label>
                       <input 
                         type="password"
                         placeholder="Minimum 8 characters"
                         value={password}
                         onChange={(e) => setPassword(e.target.value)}
                         className="w-full p-5 bg-background border border-border rounded-3xl text-sm focus:border-foreground/40 transition-all"
                       />
                       <div className="flex gap-1 px-4 mt-2">
                          {[1,2,3,4].map(i => (
                            <div key={i} className={`h-1 flex-1 rounded-full transition-all ${getPasswordStrength(password) >= i ? 'bg-foreground shadow-xl' : 'bg-foreground/5'}`} />
                          ))}
                       </div>
                    </div>

                    <div className="space-y-2">
                       <label className="text-[10px] font-black uppercase tracking-widest text-foreground/20 ml-4">Confirm Password</label>
                       <input 
                         type="password"
                         placeholder="Repeat password"
                         value={confirmPassword}
                         onChange={(e) => setConfirmPassword(e.target.value)}
                         className="w-full p-5 bg-background border border-border rounded-3xl text-sm focus:border-foreground/40 transition-all"
                       />
                    </div>

                    <div className="space-y-2">
                       <label className="text-[10px] font-black uppercase tracking-widest text-foreground/20 ml-4">Backup Hint (Optional)</label>
                       <input 
                         type="text"
                         placeholder="Wait, what was it?"
                         value={hint}
                         onChange={(e) => setHint(e.target.value)}
                         className="w-full p-5 bg-background border border-border rounded-3xl text-sm focus:border-foreground/40 transition-all"
                       />
                    </div>
                  </div>

                  {error && (
                    <p className="text-red-500 text-xs text-center font-bold uppercase tracking-widest">{error}</p>
                  )}

                  <button
                    onClick={handlePasswordSubmit}
                    disabled={isLoading || !password || password !== confirmPassword || getPasswordStrength(password) < 2}
                    className="w-full py-5 bg-foreground text-background rounded-3xl font-black uppercase tracking-widest text-xs disabled:opacity-50 transition-all shadow-xl"
                  >
                    {isLoading ? 'Securing...' : 'Verify & Backup'}
                  </button>
                </div>
              )}

              {step === 'export' && (
                <div className="space-y-8 py-4">
                  <div className="text-center">
                    <div className="w-16 h-16 rounded-3xl bg-foreground/5 border border-border flex items-center justify-center mx-auto mb-6">
                      <FileJson size={32} className="text-foreground" />
                    </div>
                    <h3 className="text-2xl font-black mb-2 text-foreground">Export Metadata</h3>
                    <p className="text-sm text-foreground/40">Download keys to your vault</p>
                  </div>

                  <div className="bg-yellow-500/5 border border-yellow-500/20 rounded-3xl p-6">
                    <div className="flex gap-4">
                       <AlertTriangle size={24} className="text-yellow-500 shrink-0" />
                       <div className="space-y-2">
                          <p className="text-xs font-bold text-yellow-500 uppercase tracking-widest">Warning</p>
                          <p className="text-[11px] text-yellow-500/60 leading-relaxed font-medium">
                            This file contains your encrypted private key. Store it in a secure location like a password manager or offline drive.
                          </p>
                       </div>
                    </div>
                  </div>

                  <div className="grid gap-6">
                    <div className="space-y-2">
                       <label className="text-[10px] font-black uppercase tracking-widest text-foreground/20 ml-4">Password to encrypt file</label>
                       <input 
                         type="password"
                         value={password}
                         onChange={(e) => setPassword(e.target.value)}
                         className="w-full p-5 bg-background border border-border rounded-3xl text-sm focus:border-foreground/40 transition-all"
                       />
                    </div>

                    <div className="space-y-2">
                       <label className="text-[10px] font-black uppercase tracking-widest text-foreground/20 ml-4">Confirm Encryption Password</label>
                       <input 
                         type="password"
                         value={confirmPassword}
                         onChange={(e) => setConfirmPassword(e.target.value)}
                         className="w-full p-5 bg-background border border-border rounded-3xl text-sm focus:border-foreground/40 transition-all"
                       />
                    </div>
                  </div>

                  {error && (
                    <p className="text-red-500 text-xs text-center font-bold uppercase tracking-widest">{error}</p>
                  )}

                  <button
                    onClick={handleDownloadBackup}
                    disabled={isLoading || !password || password !== confirmPassword}
                    className="w-full py-5 bg-foreground text-background rounded-3xl font-black uppercase tracking-widest text-xs flex items-center justify-center gap-3 transition-all shadow-xl"
                  >
                    <Download size={16} />
                    {isLoading ? 'Generating File...' : 'Download & Save Backup'}
                  </button>
                </div>
              )}

              {step === 'success' && (
                <div className="text-center py-12">
                   <motion.div 
                     initial={{ scale: 0 }}
                     animate={{ scale: 1 }}
                     className="w-24 h-24 rounded-full bg-foreground/5 border border-border flex items-center justify-center mx-auto mb-8 shadow-xl"
                   >
                     <CheckCircle2 size={48} className="text-foreground" />
                   </motion.div>
                   <h3 className="text-3xl font-black mb-4 text-foreground">You're Protected</h3>
                   <p className="text-foreground/40 text-sm max-w-xs mx-auto mb-10 font-medium">
                     Your message keys are safely backed up to Argentum Shield. You can now recover your conversations on any device.
                   </p>
                   <button
                     onClick={onClose}
                     className="px-12 py-5 bg-foreground text-background rounded-[2rem] font-black uppercase tracking-widest text-xs transition-shadow shadow-xl"
                   >
                     Done
                   </button>
                </div>
              )}
            </div>
          </motion.div>
        </div>
      )}
    </AnimatePresence>
  )
}

