const REACTION_TYPES = [
  { type: 'like', emoji: '👍', label: 'Like', color: 'rgba(59, 130, 246, 0.5)', glow: 'shadow-[0_0_15px_rgba(59,130,246,0.5)]' },
  { type: 'love', emoji: '❤️', label: 'Love', color: 'rgba(239, 68, 68, 0.5)', glow: 'shadow-[0_0_15px_rgba(239,68,68,0.5)]' },
  { type: 'fire', emoji: '🔥', label: 'Fire', color: 'rgba(249, 115, 22, 0.5)', glow: 'shadow-[0_0_15px_rgba(249,115,22,0.5)]' },
  { type: 'mind_blown', emoji: '🤯', label: 'Mind Blown', color: 'rgba(168, 85, 247, 0.5)', glow: 'shadow-[0_0_15px_rgba(168,85,247,0.5)]' },
  { type: 'support', emoji: '💪', label: 'Support', color: 'rgba(34, 197, 94, 0.5)', glow: 'shadow-[0_0_15_px_rgba(34,197,94,0.5)]' },
  { type: 'thinking', emoji: '🤔', label: 'Thinking', color: 'rgba(234, 179, 8, 0.5)', glow: 'shadow-[0_0_15px_rgba(234,179,8,0.5)]' },
]

interface ReactionButtonProps {
  postId: string
  initialReactions?: PostReaction[]
  currentUserId?: string
}

export default function ReactionButton({ postId, initialReactions = [], currentUserId }: ReactionButtonProps) {
  const supabase = createClient()
  const router = useRouter()
  const [reactions, setReactions] = useState<PostReaction[]>(initialReactions)
  const [showPicker, setShowPicker] = useState(false)
  const [loading, setLoading] = useState(false)

  useEffect(() => {
    const channel = supabase
      .channel(`post-reactions:${postId}`)
      .on(
        'postgres_changes',
        { event: '*', schema: 'public', table: 'post_reactions', filter: `post_id=eq.${postId}` },
        () => fetchReactions()
      )
      .subscribe()

    return () => {
      supabase.removeChannel(channel)
    }
  }, [postId])

  const fetchReactions = async () => {
    const { data } = await supabase
      .from('post_reactions')
      .select('*, users(username, avatar_url, display_name)')
      .eq('post_id', postId)
    if (data) setReactions(data)
  }

  const handleReaction = async (type: string) => {
    if (!currentUserId) {
      router.push('/auth/login')
      return
    }

    setLoading(true)
    setShowPicker(false)

    const existing = reactions.find(r => r.user_id === currentUserId)
    const oldReactions = [...reactions]

    if (existing) {
      if (existing.reaction === type) {
        setReactions(prev => prev.filter(r => r.user_id !== currentUserId))
      } else {
        setReactions(prev => prev.map(r => r.user_id === currentUserId ? { ...r, reaction: type } : r))
      }
    } else {
      setReactions(prev => [...prev, { 
        id: 'temp-' + Date.now(),
        user_id: currentUserId, 
        reaction: type, 
        post_id: postId,
        created_at: new Date().toISOString()
      }])
    }

    try {
      if (existing) {
        if (existing.reaction === type) {
          await supabase.from('post_reactions').delete().eq('id', existing.id)
        } else {
          await supabase.from('post_reactions').update({ reaction: type }).eq('id', existing.id)
        }
      } else {
        await supabase.from('post_reactions').insert({
          post_id: postId,
          user_id: currentUserId,
          reaction: type
        })
      }
    } catch (err) {
      setReactions(oldReactions)
    } finally {
      setLoading(false)
    }
  }

  const userReaction = reactions.find(r => r.user_id === currentUserId)
  const reactionCounts = reactions.reduce((acc: Record<string, number>, r) => {
    acc[r.reaction] = (acc[r.reaction] || 0) + 1
    return acc
  }, {})

  const sortedReactions = Object.entries(reactionCounts)
    .sort(([, a], [, b]) => (b as number) - (a as number))
    .slice(0, 3)

  const currentReactionInfo = userReaction 
    ? REACTION_TYPES.find(t => t.type === userReaction.reaction) 
    : null

  return (
    <div className="relative flex flex-col items-center gap-1 group/reaction">
      <div 
        className="relative"
        onMouseEnter={() => setShowPicker(true)}
        onMouseLeave={() => setShowPicker(false)}
      >
        <AnimatePresence>
          {showPicker && (
            <motion.div 
              initial={{ opacity: 0, y: 10, scale: 0.8 }}
              animate={{ opacity: 1, y: 0, scale: 1 }}
              exit={{ opacity: 0, y: 10, scale: 0.8 }}
              className="absolute bottom-full left-1/2 -translate-x-1/2 mb-3 p-1.5 bg-card border border-border rounded-full flex items-center gap-0.5 shadow-2xl z-50 backdrop-blur-xl"
            >
              {REACTION_TYPES.map((r, i) => (
                <motion.button
                  key={r.type}
                  initial={{ scale: 0 }}
                  animate={{ scale: 1 }}
                  transition={{ delay: i * 0.04, type: 'spring', stiffness: 300, damping: 20 }}
                  onClick={() => handleReaction(r.type)}
                  className="p-2 text-xl hover:scale-150 hover:-translate-y-2 transition-all duration-300 rounded-full hover:bg-foreground/5"
                  title={r.label}
                >
                  {r.emoji}
                </motion.button>
              ))}
            </motion.div>
          )}
        </AnimatePresence>

        <button
          onClick={() => handleReaction(userReaction?.reaction || 'like')}
          className={`
            flex items-center gap-2 px-3 py-1.5 rounded-xl transition-all duration-300
            ${userReaction 
              ? `bg-foreground/5 ${currentReactionInfo?.glow} border border-foreground/20` 
              : 'hover:bg-foreground/5 text-foreground/40 hover:text-foreground border border-transparent'
            }
          `}
        >
          {loading ? (
            <Loader2 size={16} className="animate-spin" />
          ) : userReaction ? (
            <span className="text-base">{currentReactionInfo?.emoji}</span>
          ) : (
            <ThumbsUp size={16} />
          )}
          <span className="text-[10px] font-black uppercase tracking-widest">
            {userReaction ? currentReactionInfo?.label : 'Like'}
          </span>
        </button>
      </div>

      {reactions.length > 0 && (
        <div className="flex items-center gap-1 opacity-60 group-hover/reaction:opacity-100 transition-opacity">
          <div className="flex items-center -space-x-1">
            {sortedReactions.map(([type]) => (
              <span key={type} className="text-[10px]">
                {REACTION_TYPES.find(r => r.type === type)?.emoji}
              </span>
            ))}
          </div>
          <span className="text-[9px] font-bold text-foreground/20 font-mono">
            {reactions.length}
          </span>
        </div>
      )}
    </div>
  )
}

"use client"

import { useState } from 'react'
import { createClient } from '@/lib/supabase/client'
import { Flag, X, AlertTriangle, CheckCircle2, Loader2 } from 'lucide-react'

const REPORT_REASONS = [
  { id: 'spam', label: '🚫 Spam' },
  { id: 'inappropriate', label: '⚠️ Inappropriate content' },
  { id: 'harassment', label: '😤 Harassment' },
  { id: 'misinformation', label: '❌ Misinformation' },
  { id: 'other', label: '📝 Other' },
]

interface ReportModalProps {
  isOpen: boolean
  onClose: () => void
  postId: string
  currentUserId: string
}

export default function ReportModal({ isOpen, onClose, postId, currentUserId }: ReportModalProps) {
  const supabase = createClient()
  const [reason, setReason] = useState('')
  const [details, setDetails] = useState('')
  const [loading, setLoading] = useState(false)
  const [success, setSuccess] = useState(false)
  const [error, setError] = useState('')

  if (!isOpen) return null

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault()
    if (!reason) return
    setLoading(true)
    setError('')

    try {
      const { error: submitError } = await supabase.from('reports').insert({
        reporter_id: currentUserId,
        post_id: postId,
        reason,
        details,
        status: 'pending'
      })

      if (submitError) {
        if (submitError.code === '23505') {
          setError("You've already reported this post.")
        } else {
          throw submitError
        }
      } else {
        setSuccess(true)
        setTimeout(() => {
          onClose()
          setSuccess(false)
          setReason('')
          setDetails('')
        }, 2000)
      }
    } catch (err: any) {
      setError("Failed to submit report. Please try again.")
    } finally {
      setLoading(false)
    }
  }

  return (
    <div className="fixed inset-0 z-[1000] flex items-center justify-center p-4 bg-background/80 backdrop-blur-md animate-fade-in">
      <div className="bg-card border border-border rounded-[2.5rem] w-full max-w-md overflow-hidden shadow-3xl">
        <div className="p-8 border-b border-border flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 rounded-xl bg-red-500/10 border border-red-500/20 flex items-center justify-center text-red-500">
              <Flag size={20} />
            </div>
            <h3 className="text-xl font-black text-foreground uppercase tracking-tighter">Report Build</h3>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-foreground/5 rounded-full transition-all text-foreground/40 hover:text-foreground">
            <X size={20} />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-8 flex flex-col gap-6">
          {success ? (
            <div className="py-12 flex flex-col items-center text-center gap-4 animate-scale-in">
              <div className="w-16 h-16 rounded-full bg-green-500/20 flex items-center justify-center text-green-500">
                <CheckCircle2 size={32} />
              </div>
              <div className="flex flex-col gap-2">
                <h4 className="text-xl font-bold text-foreground">Report Submitted</h4>
                <p className="text-foreground/40 text-sm">We'll review this shortly. Thank you for keeping Argentum safe.</p>
              </div>
            </div>
          ) : (
            <>
              <div className="flex flex-col gap-4">
                <label className="text-[10px] font-black text-foreground/40 uppercase tracking-widest">Reason for reporting</label>
                <div className="grid grid-cols-1 gap-2">
                  {REPORT_REASONS.map((r) => (
                    <button
                      key={r.id}
                      type="button"
                      onClick={() => setReason(r.id)}
                      className={`
                        flex items-center gap-3 p-4 rounded-2xl border transition-all text-left
                        ${reason === r.id 
                          ? 'bg-foreground/5 border-foreground/40 text-foreground' 
                          : 'bg-foreground/5 border-border text-foreground/40 hover:border-foreground/10'
                        }
                      `}
                    >
                      <span className="text-sm font-bold">{r.label}</span>
                    </button>
                  ))}
                </div>
              </div>

              <div className="flex flex-col gap-4">
                <label className="text-[10px] font-black text-foreground/40 uppercase tracking-widest">Additional Details (Optional)</label>
                <textarea
                  value={details}
                  onChange={(e) => setDetails(e.target.value)}
                  placeholder="Tell us more about why you're reporting this..."
                  className="w-full bg-foreground/5 border border-border rounded-2xl p-4 text-sm text-foreground focus:outline-none focus:border-foreground/20 transition-all min-h-[100px] resize-none"
                />
              </div>

              {error && (
                <div className="p-4 rounded-xl bg-red-500/10 border border-red-500/20 flex items-center gap-3 text-red-500 text-xs font-bold uppercase tracking-widest">
                  <AlertTriangle size={16} />
                  {error}
                </div>
              )}

              <div className="flex gap-4 mt-2">
                <button
                  type="button"
                  onClick={onClose}
                  className="flex-1 px-6 py-4 rounded-2xl bg-foreground/5 border border-border text-[10px] font-black text-foreground/40 uppercase tracking-widest hover:bg-foreground/10 transition-all"
                >
                  Cancel
                </button>
                <button
                  type="submit"
                  disabled={!reason || loading}
                  className="flex-1 silver-metallic px-6 py-4 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:brightness-110 active:scale-95 transition-all disabled:opacity-50 disabled:grayscale"
                >
                  {loading ? <Loader2 size={16} className="animate-spin mx-auto" /> : 'Submit Report'}
                </button>
              </div>
            </>
          )}
        </form>
      </div>
    </div>
  )
}

